// 1 slot dedicado de GM + 7 slots de jogador. Cada aba escolhe um perfil via
// sessionStorage; assim 8 abas no mesmo navegador podem simular GM + 7 jogadores.
const PROFILE_SLOTS = [
  { id: 'slot-gm', role: 'master', label: 'Mestre',    sub: 'Conduz a partida' },
  { id: 'slot-1',  role: 'player', label: 'Jogador 1', sub: 'Slot 01' },
  { id: 'slot-2',  role: 'player', label: 'Jogador 2', sub: 'Slot 02' },
  { id: 'slot-3',  role: 'player', label: 'Jogador 3', sub: 'Slot 03' },
  { id: 'slot-4',  role: 'player', label: 'Jogador 4', sub: 'Slot 04' },
  { id: 'slot-5',  role: 'player', label: 'Jogador 5', sub: 'Slot 05' },
  { id: 'slot-6',  role: 'player', label: 'Jogador 6', sub: 'Slot 06' },
  { id: 'slot-7',  role: 'player', label: 'Jogador 7', sub: 'Slot 07' },
];
const getActiveProfile = () => {
  try { return window.sessionStorage.getItem('cyberapp:activeProfile') || null; } catch (e) { return null; }
};
const setActiveProfile = (slotId) => {
  try {
    if (slotId) window.sessionStorage.setItem('cyberapp:activeProfile', slotId);
    else window.sessionStorage.removeItem('cyberapp:activeProfile');
  } catch (e) {}
};
const profileKey = (slotId, suffix) => `cyberapp:${slotId}:${suffix}`;
// Lock por perfil: uma aba "segura" um slot. Heartbeat a cada 5s, expira em 15s
// (cobre fechar aba sem cleanup). Outras abas veem "EM USO EM OUTRA ABA".
const PROFILE_LOCK_PREFIX = 'cyberapp:lock:';
const profileLockKey = (slotId) => `${PROFILE_LOCK_PREFIX}${slotId}`;
const isSlotLockedByOther = (slotId, tabId) => {
  try {
    const raw = window.localStorage.getItem(profileLockKey(slotId));
    if (!raw) return false;
    const cur = JSON.parse(raw);
    return cur.tabId !== tabId && Date.now() - cur.ts < 15000;
  } catch (e) { return false; }
};
const acquireProfileLock = (slotId, tabId) => {
  try {
    if (isSlotLockedByOther(slotId, tabId)) return false;
    const lockData = { tabId, ts: Date.now() };
    window.localStorage.setItem(profileLockKey(slotId), JSON.stringify(lockData));
    firebaseWrite(`shared/locks/${slotId}`, lockData);
    return true;
  } catch (e) { return true; }
};
const releaseProfileLock = (slotId, tabId) => {
  try {
    const raw = window.localStorage.getItem(profileLockKey(slotId));
    if (raw && JSON.parse(raw).tabId === tabId) {
      window.localStorage.removeItem(profileLockKey(slotId));
      firebaseWrite(`shared/locks/${slotId}`, null);
    }
  } catch (e) {}
};
// Aliases legados (mantém código antigo funcionando até refatorar).
const GM_LOCK_KEY = profileLockKey('slot-gm');
const acquireGmLock = (tabId) => acquireProfileLock('slot-gm', tabId);
const releaseGmLock = (tabId) => releaseProfileLock('slot-gm', tabId);

