// ============== BUFFS OCULTOS (anti-frustração) ==============
// Aplicados ao D20 de acerto sem aparecer no log. Regra geral: UM SÓ buff por rolagem (maior vence).
// Streak per-player vive em tablePlayers[name].streak = {
//   missesInRow, fumbledLast, lastAllyKORound
// }
// Streak per-NPC vive em summonedNPCs[i].streak = { missesInRow }
const HIDDEN_BUFFS = [
  // (1) STREAK FORGIVENESS · 2 erros seguidos → +10 no próximo D20.
  { kind: 'miss-streak', value: 10, test: (s) => (s?.missesInRow || 0) >= 2 },
  // (7) COMEBACK DO FUMBLE · após tirar nat-1 → +5 no próximo D20.
  { kind: 'fumble-comeback', value: 5, test: (s) => !!s?.fumbledLast },
  // (3) VINGANÇA · aliado caiu na rodada anterior → +5 na próxima ofensiva.
  { kind: 'revenge', value: 5, test: (s, ctx) =>
      s?.lastAllyKORound != null && (ctx.combatRound - s.lastAllyKORound) <= 1 },
  // (2) LAST STAND · HP ≤ 25% do max → +5 no próximo D20.
  { kind: 'last-stand', value: 5, test: (s, ctx) =>
      ctx.hp > 0 && ctx.maxHp > 0 && (ctx.hp / ctx.maxHp) <= 0.25 },
];
const computeHiddenBuff = (streak, ctx) => {
  let best = { value: 0, kind: null };
  for (const b of HIDDEN_BUFFS) {
    if (b.test(streak, ctx) && b.value > best.value) best = { value: b.value, kind: b.kind };
  }
  return best;
};
const computeHiddenEnemyBuff = (streak) => {
  // Enemy miss streak (3 erros seguidos → +10).
  if ((streak?.missesInRow || 0) >= 3) return { value: 10, kind: 'enemy-miss-streak' };
  return { value: 0, kind: null };
};

