// ============== TELA: WELCOME ==============
// Slideshow lento de cenários no fundo da home. Cross-fade entre duas camadas.
// Cada reinício do app sorteia uma imagem inicial diferente (useState lazy init).
const HomeBgSlideshow = () => {
  const pool = React.useMemo(() => {
    const list = [...CENARIOS_POOL, IMG_CEREBRO_VAZANTE, IMG_PORTOES, IMG_SETOR_INDUSTRIAL, IMG_TORRE, IMG_BATALHA_FINAL].filter(Boolean);
    return list.length ? list : [IMG_CEREBRO_VAZANTE];
  }, []);
  const [a, setA] = useState(() => pool[Math.floor(Math.random() * pool.length)]);
  const [b, setB] = useState(() => pool[Math.floor(Math.random() * pool.length)]);
  const [showA, setShowA] = useState(true);

  useEffect(() => {
    if (pool.length < 2) return;
    const id = setInterval(() => {
      const cur = showA ? a : b;
      let next = cur;
      let tries = 0;
      while (next === cur && tries++ < 10) next = pool[Math.floor(Math.random() * pool.length)];
      if (showA) setB(next); else setA(next);
      requestAnimationFrame(() => setShowA(s => !s));
    }, 12000);
    return () => clearInterval(id);
  }, [a, b, showA, pool]);

  const layerBase = {
    position: 'absolute', top: 0, left: 0, right: 0, height: '50%',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    opacity: 0.25,
    transition: 'opacity 3s ease-in-out',
    maskImage: 'linear-gradient(180deg, #000 0%, transparent 100%)',
    WebkitMaskImage: 'linear-gradient(180deg, #000 0%, transparent 100%)',
  };
  return (
    <>
      <div style={{ ...layerBase, backgroundImage: `url(${a})`, opacity: showA ? 0.25 : 0 }} />
      <div style={{ ...layerBase, backgroundImage: `url(${b})`, opacity: showA ? 0 : 0.25 }} />
    </>
  );
};

// HoldButton: pressionar e segurar por N ms (default 3000) pra confirmar a ação.
// Mostra um círculo conic enchendo conforme o progresso. Solta antes → cancela.
const HoldButton = ({ onComplete, disabled, color = '#FCEE0A', ringColor, holdMs = 3000, baseStyle, children }) => {
  const [progress, setProgress] = useState(0);
  const startRef = useRef(null);
  const rafRef = useRef(null);

  const cancel = () => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    rafRef.current = null;
    startRef.current = null;
    setProgress(0);
  };

  const start = (e) => {
    if (disabled) return;
    e.preventDefault();
    startRef.current = Date.now();
    const tick = () => {
      if (!startRef.current) return;
      const elapsed = Date.now() - startRef.current;
      const p = Math.min(1, elapsed / holdMs);
      setProgress(p);
      if (p >= 1) {
        cancel();
        onComplete && onComplete();
      } else {
        rafRef.current = requestAnimationFrame(tick);
      }
    };
    rafRef.current = requestAnimationFrame(tick);
  };

  useEffect(() => () => { if (rafRef.current) cancelAnimationFrame(rafRef.current); }, []);

  const pressing = progress > 0;
  const ring = ringColor || color;

  return (
    <button
      onPointerDown={start}
      onPointerUp={cancel}
      onPointerLeave={cancel}
      onPointerCancel={cancel}
      onContextMenu={(e) => e.preventDefault()}
      disabled={disabled}
      className="clip-corner-sm"
      style={{
        cursor: disabled ? 'not-allowed' : 'pointer',
        position: 'relative',
        overflow: 'hidden',
        userSelect: 'none',
        WebkitUserSelect: 'none',
        touchAction: 'none',
        ...baseStyle,
      }}
    >
      <span style={{
        position: 'relative', zIndex: 2,
        opacity: pressing ? 0.18 : 1,
        transition: 'opacity 0.15s',
      }}>{children}</span>
      {pressing && (
        <div style={{
          position: 'absolute', inset: 0, zIndex: 3,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          pointerEvents: 'none',
        }}>
          <div style={{
            width: 34, height: 34, borderRadius: '50%',
            background: `conic-gradient(${color} ${progress * 360}deg, rgba(0,0,0,0.45) ${progress * 360}deg)`,
            border: `2px solid ${ring}`,
            boxShadow: `0 0 12px ${color}99`,
          }} />
          <div className="mono" style={{
            position: 'absolute',
            top: 'calc(50% + 26px)', left: '50%',
            transform: 'translateX(-50%)',
            fontSize: 8, color: ring, letterSpacing: '0.25em',
            fontWeight: 700, whiteSpace: 'nowrap',
            textShadow: `0 0 4px ${color}`,
          }}>SEGURE {Math.ceil((1 - progress) * (holdMs / 1000))}s</div>
        </div>
      )}
    </button>
  );
};

// ============== TELA: MASTER HOME ==============
const formatTime = (s) => {
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
};

// ===== Loja (vendedor aleatório por raridade) =====
const SHOP_VENDOR_NAMES = [
  'Yuki "Pulso" Tanaka', 'Marcus Volkov', 'Zero-K', 'Lin "Estática" Wei',
  'Boss Kuro', 'Vex Salgado', 'Kira Neon', 'Old Dog Rincon',
  'Mama Zheng', 'Glitchman', 'Solana Ferro', 'Doc Vapor',
];
// Raridades da loja alinhadas com as raridades dos itens (Lixo · Normal · Vermelha · Excelente · Lendária).
// "Vermelha" = item rarity 'bom' (vermelho #FF003C). Cada loja tem um orçamento que limita
// quanto o vendedor pode pagar por itens vendidos pelos jogadores.
const SHOP_RARITIES = [
  { id: 'lixo',      label: 'Sucata',    color: '#9AA0A6', budget: 2000  },
  { id: 'normal',    label: 'Normal',    color: '#FCEE0A', budget: 5000  },
  { id: 'bom',       label: 'Vermelha',  color: '#FF003C', budget: 10000 },
  { id: 'excelente', label: 'Excelente', color: '#B026FF', budget: 15000 },
  { id: 'lendario',  label: 'Lendária',  color: '#FF00FF', budget: 20000 },
];
// Orçamento atual do vendedor — usa `vendorMoney` se presente; senão (loja legada
// sem o campo) deriva do orçamento padrão da raridade. Garante que toda loja exibe
// um valor coerente mesmo se foi criada antes da introdução do orçamento.
// Migra ids antigos (comum/raro/epico) pros novos (normal/bom/excelente). Lendário inalterado.
const LEGACY_SHOP_RARITY_MAP = { comum: 'normal', raro: 'bom', epico: 'excelente' };
const normalizeShopRarityId = (id) => LEGACY_SHOP_RARITY_MAP[id] || id;
const getShopBudgetByRarity = (rarityId) =>
  SHOP_RARITIES.find(r => r.id === normalizeShopRarityId(rarityId))?.budget ?? 0;
const getShopVendorMoney = (shop) => {
  if (!shop) return 0;
  if (Number.isFinite(shop.vendorMoney)) return shop.vendorMoney;
  return getShopBudgetByRarity(shop.rarityId);
};
// Sorteia N templates únicos de uma categoria do ITEMS_CATALOG.
const pickRandomTemplates = (category, count) => {
  const pool = ITEMS_CATALOG.filter(t => t.category === category);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
};
const generateShop = (rarityId) => {
  const rarity = SHOP_RARITIES.find(r => r.id === rarityId) || SHOP_RARITIES[0];
  const vendor = SHOP_VENDOR_NAMES[Math.floor(Math.random() * SHOP_VENDOR_NAMES.length)];
  // 7 itens fixos: 3 consumíveis (infinitos) + 2 implantes + 2 armas (estoque 1-3 aleatório).
  const consumables = pickRandomTemplates('consumable', 3);
  const implants    = pickRandomTemplates('implant', 2);
  const weapons     = pickRandomTemplates('weapon', 2);
  const buildEntry = (tpl, stock) => {
    const inst = makeItem(tpl.id, rarity.id);
    return { ...inst, rarityColor: getRarityColor(rarity.id), stock };
  };
  const items = [
    ...consumables.map(t => buildEntry(t, null)),                                  // null = infinito
    ...implants.map(t => buildEntry(t, 1 + Math.floor(Math.random() * 3))),        // 1..3
    ...weapons.map(t => buildEntry(t, 1 + Math.floor(Math.random() * 3))),         // 1..3
  ];
  return {
    vendor,
    rarityId: rarity.id,
    rarityLabel: rarity.label,
    rarityColor: rarity.color,
    items,
    vendorMoney: rarity.budget,
    vendorBudget: rarity.budget,
    openedAt: Date.now(),
  };
};

