const MasterHome = ({ onNav, shared, setShared, addLog, showToast, onOpenMenu, realPlayerName, onlinePlayerNames = [], ausenteNames = [], onFinalize }) => {
  const [confirmFinalize, setConfirmFinalize] = useState(false);
  const [rolling, setRolling] = useState(null);
  const [lastRoll, setLastRoll] = useState(null);
  const [confirmCombatStart, setConfirmCombatStart] = useState(false);
  const [noPlayersAlert, setNoPlayersAlert] = useState(false);
  const [carryConfirm, setCarryConfirm] = useState(null); // { newId, allies }
  const [initiativeModal, setInitiativeModal] = useState(null); // { rolls, order } | null
  const [damagePickerOpen, setDamagePickerOpen] = useState(false);
  const [shopPickerOpen, setShopPickerOpen] = useState(false);

  const openShopWithRarity = (rarityId) => {
    const shop = generateShop(rarityId);
    const vendorInstanceId = `vendor-${Date.now()}`;
    setShared(s => {
      // Vendedor ocupa slot de NPC aliado (se há espaço)
      const currentNPCs = s.summonedNPCs || [];
      if (currentNPCs.length >= MAX_SCENE_NPCS) {
        return { ...s, activeShop: { ...shop, vendorInstanceId: null } };
      }
      const vendorInst = {
        instanceId: vendorInstanceId,
        name: shop.vendor,
        diffId: 'friend',
        hp: 30,
        maxHp: 30,
        dmg: 0,
        isVendor: true,
        traits: ['Pacífico', 'Comerciante'],
      };
      return {
        ...s,
        activeShop: { ...shop, vendorInstanceId },
        summonedNPCs: [...currentNPCs, vendorInst],
      };
    });
    addLog({ kind: 'shop-open', text: `Loja ${shop.rarityLabel} aberta por ${shop.vendor} — ${shop.items.length} itens · vendedor entrou na cena`, color: shop.rarityColor });
    showToast(`${shop.vendor.toUpperCase()} CHEGOU À MESA`, shop.rarityColor);
  };
  const closeActiveShop = () => {
    const vendor = shared.activeShop?.vendor;
    const vendorId = shared.activeShop?.vendorInstanceId;
    setShared(s => ({
      ...s,
      activeShop: null,
      summonedNPCs: (s.summonedNPCs || []).filter(i => i.instanceId !== vendorId),
    }));
    addLog({ kind: 'shop-close', text: `Loja de ${vendor} fechou e vendedor saiu da cena`, color: C.magenta });
    showToast('LOJA FECHADA', C.magenta);
    setShopPickerOpen(false);
  };

  // Lança iniciativa quando muda de ato OU quando entra um jogador real.
  // Se não houver jogador real ainda, espera (não mostra modal vazio).
  useEffect(() => {
    const activeNames = getActivePlayerNames(shared);
    if (activeNames.length === 0) return; // ninguém pra rolar — espera ter jogador
    // Re-rola se mudou o ato OU se a lista de jogadores mudou desde a última rolagem
    const prevAct = shared.initiative?.act;
    const prevOrder = shared.initiative?.order || [];
    const sameAct = prevAct === shared.currentPoint;
    const sameRoster = sameAct && prevOrder.length === activeNames.length && activeNames.every(n => prevOrder.includes(n));
    if (sameRoster) return;
    const result = rollInitiativeForAct(shared);
    setShared(s => ({ ...s, initiative: { ...result, act: s.currentPoint } }));
    setInitiativeModal(result);
    const ordered = result.order.map(n => `${n} (${result.rolls[n]})`).join(' > ');
    addLog({ kind: 'initiative', text: `Iniciativa do ato ${String(shared.currentPoint).padStart(2,'0')}: ${ordered} > Inimigos`, color: C.cyan });
  }, [shared.currentPoint, shared.initiative?.act, (shared.tablePlayers || []).length, (shared.kickedPlayers || []).length]);

  // Iniciar combate
  const tryStartCombat = () => {
    if ((onlinePlayerNames || []).length === 0) {
      setNoPlayersAlert(true);
      return;
    }
    const enemies = (shared.summonedNPCs || []).filter(i => getDifficulty(i.diffId).type !== 'ally');
    if (enemies.length === 0) {
      showToast('SEM INIMIGOS NA CENA', C.magenta);
      return;
    }
    setConfirmCombatStart(true);
  };

  const startCombat = () => {
    const hadShop = !!shared.activeShop;
    const vendorName = shared.activeShop?.vendor;
    const vendorId = shared.activeShop?.vendorInstanceId;
    setShared(s => {
      // Espanta o vendedor se houver loja ativa
      const cleanedNPCs = vendorId
        ? (s.summonedNPCs || []).filter(i => i.instanceId !== vendorId)
        : (s.summonedNPCs || []);
      const cleanedState = { ...s, summonedNPCs: cleanedNPCs, activeShop: null };
      return {
        ...cleanedState,
        combat: {
          active: true, round: 1, turnIndex: 0,
          queue: buildCombatQueue(cleanedState),
          koThisRound: [],
        },
      };
    });
    addLog({ kind: 'combat-start', text: '⚔ COMBATE INICIADO', color: C.magenta });
    if (hadShop) {
      addLog({ kind: 'shop-close', text: `O vendedor foi espantado — ${vendorName} fugiu da mesa`, color: C.magenta });
      showToast('O VENDEDOR FOI ESPANTADO', C.magenta);
      setTimeout(() => showToast('COMBATE INICIADO', C.magenta), 1500);
    } else {
      showToast('COMBATE INICIADO', C.magenta);
    }
    setConfirmCombatStart(false);
  };

  // Helpers do state-machine de combate (eventos visuais sincronizados)
  const setCombatEvent = (eventOrUpdater) => {
    setShared(s => {
      if (!s.combat) return s;
      const event = typeof eventOrUpdater === 'function' ? eventOrUpdater(s.combat.event) : eventOrUpdater;
      return { ...s, combat: { ...s.combat, event } };
    });
  };

  // Avançar turno (versão modal-driven): emite eventos pra criar a experiência visual.
  const advanceTurn = () => {
    if (!shared.combat?.active) return;
    const queue = shared.combat.queue;
    // Usa o ator "vivo" derivado (pula inimigos/aliados eliminados).
    const current = currentActor;
    if (!current) return;
    if (shared.combat.event) return;

    const result = resolveAutoTurn(current, shared, realPlayerName);
    if (result === null) {
      showToast('AGUARDANDO JOGADOR', C.yellow);
      return;
    }

    const koAdded = (result.updates && result.updates.__koAdded) || [];
    // Quem está terminando o turno (recebe DOT + tick de status)
    const carrierKey = current.kind === 'player' ? current.name : current.instanceId;
    const dotLogs = []; // mensagens de DOT pra logar fora
    const advance = () => {
      setShared(s => {
        if (!s.combat) return s;
        let next = { ...s, ...result.updates };
        if (next.__koAdded) delete next.__koAdded;

        // ===== Aplica DOT (queimando -5, envenenado -2) ao portador cujo turno terminou
        const statusList = getCarrierStatusList(next.statusEffects || s.statusEffects, carrierKey);
        let totalDot = 0;
        statusList.forEach(st => {
          const def = getStatusDef(st.id);
          if (def && def.dot) {
            totalDot += def.dot;
            dotLogs.push(`${current.name} sofreu ${def.dot} de dano por ${def.name}`);
          }
        });
        if (totalDot > 0) {
          if (current.kind === 'player') {
            // Aplica em tablePlayer[name].hp (per-player)
            next.tablePlayers = (next.tablePlayers || s.tablePlayers || []).map(p =>
              p.name === current.name ? { ...p, hp: Math.max(0, (p.hp || 0) - totalDot) } : p
            );
          } else {
            // NPC: aplica em summonedNPCs
            next.summonedNPCs = (next.summonedNPCs || s.summonedNPCs || []).map(i =>
              i.instanceId === carrierKey ? { ...i, hp: Math.max(0, (i.hp || 0) - totalDot) } : i
            );
          }
        }
        // Tick de status do portador
        next.statusEffects = tickStatusForCarrier(next.statusEffects || s.statusEffects, carrierKey);

        // Avança a partir do índice do ator ATUAL (vivo). Pula índices subsequentes que
        // já estão mortos — inimigos eliminados não devem reaparecer no controle de rodada.
        const liveIdx = (s.combat.queue || []).findIndex(a =>
          a === current ||
          (a && a.kind === current.kind && (a.instanceId ? a.instanceId === current.instanceId : a.name === current.name))
        );
        const startIdx = liveIdx >= 0 ? liveIdx : s.combat.turnIndex;
        let newTurn = startIdx + 1;
        let newRound = s.combat.round;
        let newKo = [...(s.combat.koThisRound || []), ...koAdded];
        const summonedAfter = next.summonedNPCs || s.summonedNPCs || [];
        const tablePlayersAfter = next.tablePlayers || s.tablePlayers || [];
        const isAlive = (actor) => {
          if (!actor) return false;
          if (actor.kind === 'player') {
            const tp = tablePlayersAfter.find(p => p.name === actor.name);
            return !tp || (tp.hp ?? 1) > 0;
          }
          const inst = summonedAfter.find(i => i.instanceId === actor.instanceId);
          return !!inst && (inst.hp ?? 0) > 0;
        };
        // Avança até achar um ator vivo (ou completar a fila ↦ wrap de rodada).
        let safety = (s.combat.queue || []).length + 1;
        while (safety-- > 0) {
          if (newTurn >= s.combat.queue.length) {
            newTurn = 0;
            newRound++;
            newKo = [];
          }
          if (isAlive(s.combat.queue[newTurn])) break;
          newTurn++;
        }
        const over = checkCombatOver(next.summonedNPCs || []);
        if (over) next.combat = null;
        else next.combat = { ...s.combat, turnIndex: newTurn, round: newRound, koThisRound: newKo, event: null };
        return next;
      });
      (result.logs || []).forEach(l => addLog({ kind: 'combat-action', text: l.text, color: l.color }));
      dotLogs.forEach(t => addLog({ kind: 'status-dot', text: t, color: '#FF6E2C' }));
      if (shared.combat.turnIndex + 1 >= queue.length) {
        addLog({ kind: 'combat-round', text: `Rodada ${shared.combat.round + 1} iniciada`, color: C.yellow });
      }
    };

    // Extrai info do log resolvido pra montar o modal
    const logText = (result.logs && result.logs[0] && result.logs[0].text) || '';

    // ===== Caso: NPC inimigo atacando jogador =====
    if (current.kind === 'enemy') {
      const inst = (shared.summonedNPCs || []).find(i => i.instanceId === current.instanceId);
      const isBoss = inst && inst.diffId === 'legendary';
      // Errou a ação (50%) — visualiza com d2-batch só dele
      if (/errou a ação/.test(logText)) {
        setCombatEvent({ kind: 'd2-batch', side: 'enemy', rolls: { [current.instanceId]: 'miss' }, showCount: false });
        setTimeout(() => { setCombatEvent({ kind: 'miss', attackerName: current.name, defenderName: '—', panic: true }); }, 2200);
        setTimeout(advance, 4400);
        return;
      }
      const dodgeM = logText.match(/([^()]+?) foi desviado! \((\d+) vs (\d+) de ([^()]+?)\)/);
      const hitM = logText.match(/([^()]+?) \((\d+)\) acertou ([^()]+?) \((\d+)\) · (\d+) dano(?: · K\.O\.)?/);
      if (dodgeM) {
        const targetName = dodgeM[1].trim();
        const dRoll = +dodgeM[2], aRoll = +dodgeM[3];
        setCombatEvent({ kind: 'd2-batch', side: 'enemy', rolls: { [current.instanceId]: isBoss ? 'boss' : 'hit' }, showCount: false });
        setTimeout(() => setCombatEvent({ kind: 'attack', attackerName: current.name, defenderName: targetName, targetIsPlayer: true, aRoll, dRoll, hit: false, phase: 'rolling' }), 1800);
        setTimeout(() => setCombatEvent(e => e ? { ...e, phase: 'reveal' } : null), 3400);
        setTimeout(() => setCombatEvent({ kind: 'miss', attackerName: current.name, defenderName: targetName, dodgerKind: 'player' }), 5400);
        setTimeout(advance, 7600);
        return;
      }
      if (hitM) {
        const aRoll = +hitM[2], targetName = hitM[3].trim(), dRoll = +hitM[4], dmg = +hitM[5];
        const isKO = /K\.O\./.test(logText);
        setCombatEvent({ kind: 'd2-batch', side: 'enemy', rolls: { [current.instanceId]: isBoss ? 'boss' : 'hit' }, showCount: false });
        setTimeout(() => setCombatEvent({ kind: 'attack', attackerName: current.name, defenderName: targetName, targetIsPlayer: true, aRoll, dRoll, hit: true, phase: 'rolling' }), 1800);
        setTimeout(() => setCombatEvent(e => e ? { ...e, phase: 'reveal' } : null), 3400);
        setTimeout(() => setCombatEvent({ kind: 'damage', defenderName: targetName, dmg, isKO }), 5400);
        setTimeout(advance, 8000);
        return;
      }
      advance();
      return;
    }

    // ===== Caso: NPC aliado atacando inimigo =====
    if (current.kind === 'ally') {
      const dodgeM = logText.match(/([^()]+?) \((\d+)\) errou em ([^()]+?) \((\d+)\)/);
      const hitM = logText.match(/([^()]+?) \((\d+)\) acertou ([^()]+?) \((\d+)\) · (\d+) dano(?: · ELIMINADO)?/);
      if (dodgeM) {
        const aRoll = +dodgeM[2], targetName = dodgeM[3].trim(), dRoll = +dodgeM[4];
        setCombatEvent({ kind: 'attack', attackerName: current.name, defenderName: targetName, aRoll, dRoll, hit: false, phase: 'rolling' });
        setTimeout(() => setCombatEvent(e => e ? { ...e, phase: 'reveal' } : null), 1800);
        setTimeout(() => setCombatEvent({ kind: 'miss', attackerName: current.name, defenderName: targetName, dodgerKind: 'enemy' }), 3800);
        setTimeout(advance, 6000);
        return;
      }
      if (hitM) {
        const aRoll = +hitM[2], targetName = hitM[3].trim(), dRoll = +hitM[4], dmg = +hitM[5];
        const isKO = /ELIMINADO/.test(logText);
        setCombatEvent({ kind: 'attack', attackerName: current.name, defenderName: targetName, aRoll, dRoll, hit: true, phase: 'rolling' });
        setTimeout(() => setCombatEvent(e => e ? { ...e, phase: 'reveal' } : null), 1800);
        setTimeout(() => setCombatEvent({ kind: 'damage', defenderName: targetName, dmg, isKO }), 3800);
        setTimeout(advance, 6400);
        return;
      }
      setCombatEvent({ kind: 'turn-banner', text: current.name.toUpperCase(), subtitle: 'SEM ALVO · MANTÉM POSIÇÃO' });
      setTimeout(advance, 2500);
      return;
    }

    // PC fictício (não real)
    if (current.kind === 'player' && current.name !== realPlayerName) {
      const missM = logText.match(/([^()]+?) \((\d+)\) errou em ([^()]+?) \((\d+)\)/);
      const hitM = logText.match(/([^()]+?) \((\d+)\) acertou ([^()]+?) \((\d+)\) · (\d+) dano(?: · ELIMINADO)?/);
      if (missM) {
        const aRoll = +missM[2], targetName = missM[3].trim(), dRoll = +missM[4];
        setCombatEvent({ kind: 'attack', attackerName: current.name, defenderName: targetName, aRoll, dRoll, hit: false, phase: 'rolling' });
        setTimeout(() => setCombatEvent(e => e ? { ...e, phase: 'reveal' } : null), 1800);
        setTimeout(() => setCombatEvent({ kind: 'miss', attackerName: current.name, defenderName: targetName, dodgerKind: 'enemy' }), 3800);
        setTimeout(advance, 6000);
        return;
      }
      if (hitM) {
        const aRoll = +hitM[2], targetName = hitM[3].trim(), dRoll = +hitM[4], dmg = +hitM[5];
        const isKO = /ELIMINADO/.test(logText);
        setCombatEvent({ kind: 'attack', attackerName: current.name, defenderName: targetName, aRoll, dRoll, hit: true, phase: 'rolling' });
        setTimeout(() => setCombatEvent(e => e ? { ...e, phase: 'reveal' } : null), 1800);
        setTimeout(() => setCombatEvent({ kind: 'damage', defenderName: targetName, dmg, isKO }), 3800);
        setTimeout(advance, 6400);
        return;
      }
      advance();
      return;
    }

    // Fallback
    advance();
  };

  const inCombat = !!(shared.combat && shared.combat.active);
  // Pula entradas mortas (NPCs com hp<=0) ao mostrar/avançar — inimigos/aliados eliminados
  // não devem aparecer no botão de controle de rodada.
  const isActorAlive = (actor) => {
    if (!actor) return false;
    if (actor.kind === 'player') return true; // jogador KO é tratado no fluxo do próprio
    const inst = (shared.summonedNPCs || []).find(i => i.instanceId === actor.instanceId);
    return !!inst && (inst.hp ?? 0) > 0;
  };
  const liveCurrentActor = (() => {
    if (!inCombat) return null;
    const q = shared.combat.queue || [];
    for (let off = 0; off < q.length; off++) {
      const idx = (shared.combat.turnIndex + off) % q.length;
      if (isActorAlive(q[idx])) return q[idx];
    }
    return null;
  })();
  const currentActor = liveCurrentActor;
  const waitingRealPlayer = currentActor && currentActor.kind === 'player' && currentActor.name === realPlayerName;

  // Iniciar cronômetro ao entrar na home do mestre (se não estiver rodando)
  useEffect(() => {
    if (!shared.isRunning) {
      setShared(s => ({ ...s, isRunning: true }));
    }
  }, []);

  const activeJourney = (shared.timeline && shared.timeline.length) ? shared.timeline : JOURNEY_POINTS;
  const point = activeJourney.find(p => p.id === shared.currentPoint) || activeJourney[0] || JOURNEY_POINTS[1];
  const nextPoint = activeJourney.find(p => p.id === shared.currentPoint + 1);
  const prevPoint = activeJourney.find(p => p.id === shared.currentPoint - 1);

  const attemptGoToPoint = (newId) => {
    const allies = (shared.summonedNPCs || []).filter(i => getDifficulty(i.diffId).type === 'ally' && !i.isVendor);
    if (allies.length > 0) {
      setCarryConfirm({ newId, allies });
    } else {
      goToPoint(newId, false);
    }
  };

  const goToPoint = (newId, carry = false) => {
    const p = activeJourney.find(x => x.id === newId);
    const sceneNPCsNow = shared.sceneNPCs || {};
    const willRestore = (sceneNPCsNow[newId] || []).length;
    const allies = (shared.summonedNPCs || []).filter(i => getDifficulty(i.diffId).type === 'ally' && !i.isVendor);
    if (carry) {
      const destBase = sceneNPCsNow[newId] || [];
      if (destBase.length + allies.length > MAX_SCENE_NPCS) {
        showToast(`SEM ESPAÇO PARA ${allies.length} ALIADO(S) NO ATO ${String(newId).padStart(2,'0')}`, C.magenta);
        setCarryConfirm(null);
        return;
      }
    }
    const hadShop = !!shared.activeShop;
    const vendorName = shared.activeShop?.vendor;
    setShared(s => {
      // Lojas ficam na cena que foram invocadas — vendor e activeShop somem ao trocar de ato.
      // Aliados carregados saem da cena atual e vão para a destino; senão, ficam onde estavam.
      const staying = (s.summonedNPCs || []).filter(i => {
        if (i.isVendor) return false;
        if (carry && getDifficulty(i.diffId).type === 'ally') return false;
        return true;
      });
      const sceneNPCs = { ...(s.sceneNPCs || {}), [s.currentPoint]: staying };
      // Restaura inimigos da cena destino com HP cheio (penalidade por fugir).
      const restored = (sceneNPCs[newId] || []).map(inst => {
        const max = inst.maxHp || inst.hp;
        return { ...inst, hp: max };
      });
      // Aliados carregados preservam hp/dmg/traços atuais.
      const carried = carry ? allies : [];
      return {
        ...s,
        currentPoint: newId,
        sceneNPCs,
        summonedNPCs: [...restored, ...carried],
        activeShop: null,
        attrBonuses: {},
        combat: null,
        // Mudança de ato limpa TODOS os efeitos de status (queimando, congelando, etc.).
        statusEffects: {},
        // Bônus de atributo temporários (perfume, energético, etc.) acabam ao mudar de ato.
        tempAttrBonuses: {},
        // Revive caídos com 1 HP + zera luckBuff + ganha +1 sorte (cap = luckMax + implantes).
        tablePlayers: (s.tablePlayers || []).map(p => {
          const next = { ...p, luckBuff: 0 };
          if (Number.isFinite(p.hp) && p.hp <= 0) next.hp = 1;
          const implLuck = (Array.isArray(s.implantsByPlayer?.[p.name])
            ? s.implantsByPlayer[p.name].filter(i => i && i.equipped)
            : []
          ).reduce((a, i) => a + (i.luckBonus || 0), 0);
          const effLuckMax = (Number.isFinite(p.luckMax) ? p.luckMax : 5) + implLuck;
          const curLuck = Number.isFinite(p.luck) ? p.luck : 0;
          next.luck = Math.min(effLuckMax, curLuck + 1);
          return next;
        }),
      };
    });
    const carryMsg = carry && allies.length > 0 ? ` ${allies.length} aliado(s) carregado(s).` : '';
    const shopMsg = hadShop ? ` Loja de ${vendorName} fechou.` : '';
    addLog({
      kind: 'point-change',
      text: `Jornada avançou para Ato ${String(newId).padStart(2, '0')}: ${p.name}.${willRestore > 0 ? ` ${willRestore} inimigo(s) reaparecem com HP cheio.` : ''}${carryMsg}${shopMsg} Bônus resetados.`,
      color: C.purple,
    });
    showToast(`ATO ${String(newId).padStart(2, '0')}: ${p.name}`, C.purple);
    setCarryConfirm(null);
  };

  const rollDice = (type) => {
    setRolling(type);
    const max = type === 'D6' ? 6 : type === 'D20' ? 20 : 100;
    const result = Math.floor(Math.random() * max) + 1;
    setTimeout(() => {
      setRolling(null);
      setLastRoll({ type, value: result });
      const label = type === 'D6' ? 'Dano Rápido' : type === 'D20' ? 'Ação Rápida' : 'Desafio';
      addLog({
        kind: 'master-roll',
        text: `Mestre rolou ${type} (${label}): ${result}`,
        value: result,
        dice: type,
        color: type === 'D6' ? C.magenta : type === 'D20' ? C.cyan : C.yellow,
      });
    }, 800);
  };

  const applyQuickDamage = (targetKind, targetData) => {
    const dmg = Math.floor(Math.random() * 6) + 1;
    const targetName = targetData.name;
    let combatEndedNow = false;
    setShared(s => {
      let next = { ...s };
      if (targetKind === 'player') {
        // Atualiza só o HP do tablePlayer entry do jogador alvo (isolamento per-player).
        // A aba do jogador lê myHP do tablePlayer e re-renderiza.
        const list = (s.tablePlayers || []).map(p => {
          if (p.name !== targetName) return p;
          const cur = Number.isFinite(p.hp) ? p.hp : (p.maxHp || s.playerMaxHP || 20);
          const max = Number.isFinite(p.maxHp) ? p.maxHp : (s.playerMaxHP || 20);
          return { ...p, hp: Math.max(0, cur - dmg), maxHp: max };
        });
        next.tablePlayers = list;
      } else if (targetKind === 'npc') {
        next.summonedNPCs = (s.summonedNPCs || []).map(i =>
          i.instanceId === targetData.instanceId
            ? { ...i, hp: Math.max(0, (i.hp || 0) - dmg) }
            : i
        );
        // Se o combate está ativo E o último inimigo morreu agora, encerra na hora —
        // senão o jogador fica vendo o botão atacar sem alvo até alguém avançar turno.
        if (s.combat && s.combat.active) {
          const over = checkCombatOver(next.summonedNPCs);
          if (over) {
            next.combat = null;
            combatEndedNow = true;
          }
        }
      }
      return next;
    });
    setLastRoll({ type: 'D6', value: dmg });
    addLog({
      kind: 'master-damage',
      text: `Mestre aplicou ${dmg} de dano em ${targetName} (D6)`,
      color: C.magenta,
      targetPlayer: targetKind === 'player' ? targetName : undefined,
    });
    showToast(`−${dmg} HP → ${targetName.toUpperCase()}`, C.magenta);
    if (combatEndedNow) {
      addLog({ kind: 'combat-end', text: '⚔ Combate encerrado — todos inimigos derrotados', color: C.green });
    }
    setDamagePickerOpen(false);
  };

  const startGroupHack = () => {
    setShared(s => ({ ...s, pendingHack: { time: Date.now(), result: null } }));
    addLog({
      kind: 'group-challenge',
      text: 'Mestre iniciou DESAFIO DE GRUPO: Hacking',
      color: C.green,
    });
    showToast('DESAFIO DE GRUPO ENVIADO', C.green);
    onNav('master-hack');
  };

  const progress = (shared.currentPoint / activeJourney.length) * 100;

  return (
    <div style={{ minHeight: '100vh', background: C.bg, color: C.text, paddingBottom: 80 }}>
      {/* Top bar customizada com menu */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        padding: '16px 16px 12px',
        borderBottom: `1px solid ${C.border}`,
        background: C.bg,
        position: 'sticky',
        top: 0,
        zIndex: 10,
        gap: 12,
      }}>
        <button onClick={onOpenMenu} style={{
          background: 'transparent',
          border: `1px solid ${C.border}`,
          width: 36, height: 36,
          cursor: 'pointer',
          color: C.magenta,
          fontSize: 18,
        }} className="clip-corner-sm">≡</button>
        <div style={{ flex: 1, color: C.text, fontSize: 18, fontWeight: 600, letterSpacing: '0.04em', display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{
            width: 9, height: 9, borderRadius: '50%',
            background: shared.tableOnline === false ? '#FF003C' : '#00FF85',
            animation: shared.tableOnline === false ? 'none' : 'pulse-green 1.6s ease-out infinite',
            flexShrink: 0,
          }} title={shared.tableOnline === false ? 'Mesa offline' : 'Mesa online'} />
          {shared.tableOnline === false ? 'Partida Offline' : (
            <>
              Partida Ativa
              {shared.activeMesaCode && (
                <>
                  {' · '}
                  <span className="mono" style={{ color: C.yellow, fontWeight: 700, letterSpacing: '0.15em' }}>
                    {shared.activeMesaCode}
                  </span>
                </>
              )}
            </>
          )}
        </div>
        <button onClick={() => onNav('master-log')} style={{
          background: 'transparent', border: `1px solid ${C.border}`, color: C.yellow,
          padding: '6px 10px', fontSize: 11, cursor: 'pointer', fontWeight: 700,
        }} className="clip-corner-sm mono">
          LOG ({shared.log.length})
        </button>
      </div>

      {/* Progress bar */}
      <div style={{ padding: '16px 16px 8px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
          <div>
            <div className="mono" style={{ color: C.textDim, fontSize: 10, letterSpacing: '0.2em' }}>
              ATO {String(shared.currentPoint).padStart(2, '0')} / {String(activeJourney.length).padStart(2, '0')}
            </div>
            <div style={{ fontSize: 16, fontWeight: 600 }}>{point.name}</div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <div className="mono" style={{ color: C.textDim, fontSize: 9, letterSpacing: '0.2em' }}>TEMPO</div>
            <div className="mono" style={{ color: C.cyan, fontSize: 16 }}>{formatTime(shared.elapsedSeconds)}</div>
          </div>
        </div>
        <div style={{ height: 4, background: C.bg3, position: 'relative' }}>
          <div style={{ position: 'absolute', inset: 0, width: `${progress}%`, background: C.yellow, transition: 'width 0.4s' }} />
        </div>
      </div>

      {/* Navegação de atos (acima do cenário) — segurar 3s pra confirmar */}
      <div style={{ padding: '12px 16px 0', display: 'flex', gap: 8 }}>
        <HoldButton
          onComplete={() => prevPoint && attemptGoToPoint(prevPoint.id)}
          disabled={!prevPoint}
          color={C.cyan}
          baseStyle={{
            flex: 1,
            background: C.bg2,
            border: `1px solid ${prevPoint ? C.border : C.bg3}`,
            color: prevPoint ? C.text : C.textDim,
            padding: '10px',
            fontSize: 12,
            fontWeight: 600,
            letterSpacing: '0.05em',
            opacity: prevPoint ? 1 : 0.4,
          }}
        >
          ← {prevPoint ? prevPoint.name : 'INÍCIO'}
        </HoldButton>
        {nextPoint ? (
          <HoldButton
            onComplete={() => attemptGoToPoint(nextPoint.id)}
            color={'#000'}
            ringColor={'#000'}
            baseStyle={{
              flex: 1,
              background: C.yellow,
              border: `1px solid ${C.yellow}`,
              color: '#000',
              padding: '10px',
              fontSize: 12,
              fontWeight: 700,
              letterSpacing: '0.05em',
            }}
          >
            {nextPoint.name} →
          </HoldButton>
        ) : (
          /* Último ato — botão vira ENCERRAR AVENTURA */
          <HoldButton
            onComplete={() => setConfirmFinalize(true)}
            color={'#fff'}
            ringColor={'#fff'}
            baseStyle={{
              flex: 1,
              background: C.magenta,
              border: `1px solid ${C.magenta}`,
              color: '#fff',
              padding: '10px',
              fontSize: 12,
              fontWeight: 700,
              letterSpacing: '0.05em',
            }}
          >
            ✦ ENCERRAR AVENTURA
          </HoldButton>
        )}
      </div>

      {/* Modal de confirmação de encerrar aventura */}
      {confirmFinalize && (
        <div
          onClick={() => setConfirmFinalize(false)}
          style={{
            position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.85)', zIndex: 200,
            display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20,
            animation: 'fade-in 0.2s',
          }}
        >
          <div onClick={e => e.stopPropagation()} className="clip-corner" style={{
            background: C.bg2, border: `2px solid ${C.magenta}`, padding: 22, width: '100%', maxWidth: 380,
          }}>
            <div className="mono" style={{ color: C.magenta, fontSize: 11, letterSpacing: '0.3em', marginBottom: 10 }}>
              // ENCERRAR AVENTURA
            </div>
            <div style={{ fontSize: 14, fontWeight: 700, color: C.text, marginBottom: 8 }}>
              Finalizar esta campanha?
            </div>
            <div style={{ fontSize: 12, color: C.textDim, lineHeight: 1.5, marginBottom: 16 }}>
              Cada jogador recebe o código do personagem. A aventura é salva no Hall das Aventuras. A mesa será apagada depois que você confirmar a celebração.
            </div>
            <div style={{ display: 'flex', gap: 8 }}>
              <button
                onClick={() => setConfirmFinalize(false)}
                className="clip-corner-sm"
                style={{
                  flex: 1, background: 'transparent', border: `1px solid ${C.border}`,
                  color: C.textDim, padding: '10px', cursor: 'pointer',
                  fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
                }}
              >CANCELAR</button>
              <button
                onClick={() => { setConfirmFinalize(false); onFinalize && onFinalize(); }}
                className="clip-corner-sm"
                style={{
                  flex: 1, background: C.magenta, border: 'none',
                  color: '#fff', padding: '10px', cursor: 'pointer',
                  fontWeight: 900, fontSize: 12, letterSpacing: '0.15em',
                }}
              >ENCERRAR</button>
            </div>
          </div>
        </div>
      )}

      {/* Cenário */}
      <div style={{ padding: 16 }}>
        <div className="clip-corner" style={{
          height: 235,
          backgroundImage: `url(${point.img})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          position: 'relative',
          border: `1px solid ${C.border}`,
          transition: 'background-image 0.5s',
        }}>
          <div style={{
            position: 'absolute', inset: 0,
            background: 'linear-gradient(180deg, transparent 40%, rgba(10,10,15,0.95) 100%)',
          }} />
          {/* Tag EM COMBATE — agora dentro da imagem, no topo */}
          {inCombat && (
            <span className="mono" style={{
              position: 'absolute', top: 10, left: 10,
              fontSize: 10, color: '#fff',
              background: C.magenta, padding: '4px 10px',
              letterSpacing: '0.25em', fontWeight: 700,
              animation: 'glitch-flicker 1.6s infinite',
              boxShadow: `0 0 12px ${C.magenta}88`,
            }} title="Combate em andamento">⚔ EM COMBATE</span>
          )}
          <div style={{ position: 'absolute', bottom: 12, left: 14, right: 14 }}>
            <div className="mono" style={{ color: C.yellow, fontSize: 10, letterSpacing: '0.2em' }}>LOCAL ATUAL</div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>{point.name}</div>
            <div style={{ fontSize: 11, color: C.textDim, marginTop: 2 }}>{point.desc}</div>
          </div>

          {/* Slots de NPCs invocados na cena (máx 10) */}
          <div style={{
            position: 'absolute', bottom: 8, right: 8,
            display: 'grid', gridTemplateColumns: 'repeat(5, 14px)', gap: 4,
            padding: 4, background: 'rgba(0,0,0,0.35)',
            border: `1px solid rgba(255,255,255,0.08)`,
          }} className="clip-corner-sm">
            {Array.from({ length: MAX_SCENE_NPCS }).map((_, i) => {
              const inst = shared.summonedNPCs[i];
              if (!inst) {
                return <div key={i} style={{
                  width: 14, height: 14, borderRadius: '50%',
                  border: '1px solid rgba(255,255,255,0.35)',
                }} />;
              }
              const diff = getDifficulty(inst.diffId);
              const dead = (inst.hp || 0) <= 0 && inst.maxHp !== undefined;
              return (
                <div key={i} title={`${inst.name}${inst.maxHp !== undefined ? ` · ${inst.hp}/${inst.maxHp} HP` : ''}`} style={{
                  width: 14, height: 14, display: 'flex',
                  alignItems: 'center', justifyContent: 'center',
                  opacity: dead ? 0.45 : 1,
                  filter: dead ? 'grayscale(1)' : 'none',
                }}>
                  {dead ? (
                    <span style={{ color: '#888', fontSize: 14, fontWeight: 700 }}>✕</span>
                  ) : (
                    <NPCSymbol diff={diff} size={14} isVendor={inst.isVendor} />
                  )}
                </div>
              );
            })}
          </div>
        </div>

      </div>

      {/* Controle de combate (abaixo do cenário) */}
      <div style={{ padding: '4px 16px 0' }}>
        {!inCombat ? (
          <button
            onClick={tryStartCombat}
            className="clip-corner-sm"
            style={{
              width: '100%',
              background: C.bg2,
              border: `1.5px solid ${C.magenta}`,
              color: C.magenta,
              padding: '10px',
              cursor: 'pointer',
              fontWeight: 700, fontSize: 12, letterSpacing: '0.15em',
            }}
          >⚔ INICIAR COMBATE</button>
        ) : (() => {
          const queueLen = (shared.combat?.queue || []).length;
          const turnIdx = (shared.combat?.turnIndex || 0) + 1;
          const actorColor = currentActor
            ? (currentActor.kind === 'enemy' ? C.magenta
              : currentActor.kind === 'ally' ? '#00FF85'
              : C.cyan)
            : C.magenta;
          const actorLabel = currentActor
            ? (currentActor.kind === 'enemy' ? 'INIMIGO'
              : currentActor.kind === 'ally' ? 'ALIADO'
              : 'JOGADOR')
            : '—';
          const actorSym = currentActor
            ? (currentActor.kind === 'enemy' ? '✺'
              : currentActor.kind === 'ally' ? '✦'
              : '◆')
            : '·';
          const eventActive = !!shared.combat?.event;
          const disabled = waitingRealPlayer || eventActive;
          return (
            <HoldButton
              onComplete={advanceTurn}
              disabled={disabled}
              color={actorColor}
              holdMs={1000}
              baseStyle={{
                width: '100%',
                background: disabled
                  ? `linear-gradient(135deg, ${C.bg2} 0%, ${C.bg3} 100%)`
                  : `linear-gradient(135deg, ${actorColor}22 0%, ${C.bg3} 100%)`,
                border: `2px solid ${disabled ? C.border : actorColor}`,
                color: C.text,
                padding: '14px 16px',
                textAlign: 'left',
                boxShadow: disabled ? 'none' : `0 0 18px ${actorColor}33`,
                animation: disabled ? 'none' : 'pulse-yellow 1.8s infinite',
                transition: 'all 0.25s',
              }}
            >
              <div style={{
                display: 'grid',
                gridTemplateColumns: '52px 1fr auto',
                alignItems: 'center',
                gap: 14,
                width: '100%',
              }}>
              {/* Ícone play */}
              <div style={{
                width: 52, height: 52,
                borderRadius: '50%',
                background: disabled ? C.bg2 : actorColor,
                color: disabled ? C.textDim : '#000',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 26, fontWeight: 900,
                boxShadow: disabled ? 'none' : `0 0 16px ${actorColor}88`,
              }}>{waitingRealPlayer ? '⏸' : '▶'}</div>

              {/* Texto central */}
              <div style={{ minWidth: 0 }}>
                <div className="mono" style={{
                  fontSize: 9, color: disabled ? C.textDim : actorColor,
                  letterSpacing: '0.3em', fontWeight: 700,
                }}>
                  // REGENTE · RODADA {String(shared.combat?.round || 1).padStart(2, '0')} · {turnIdx}/{queueLen}
                </div>
                <div style={{
                  fontSize: 15, fontWeight: 900, color: C.text,
                  marginTop: 3, letterSpacing: '0.02em',
                  whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
                  fontFamily: "'Orbitron', sans-serif",
                }}>
                  {eventActive
                    ? 'EM ANDAMENTO...'
                    : waitingRealPlayer
                      ? `AGUARDANDO ${currentActor.name.toUpperCase()}`
                      : 'AVANÇAR TURNO'}
                </div>
                {!waitingRealPlayer && currentActor && (
                  <div className="mono" style={{
                    fontSize: 10, color: actorColor,
                    letterSpacing: '0.15em', marginTop: 2,
                    whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
                  }}>
                    {actorSym} {actorLabel} · {currentActor.name.toUpperCase()}
                  </div>
                )}
              </div>

              {/* Cronômetro / chevron */}
              <div style={{
                color: disabled ? C.textDim : actorColor,
                fontSize: 24, fontWeight: 900,
                opacity: eventActive ? 0.4 : 1,
              }}>›</div>
              </div>
            </HoldButton>
          );
        })()}
      </div>

      {/* Dados */}
      <div style={{ padding: '8px 16px' }}>
        <div className="mono" style={{ color: C.textDim, fontSize: 10, letterSpacing: '0.2em', marginBottom: 10 }}>
          // DADOS RÁPIDOS
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
          <DiceButton type="D6" label="Dano Rápido" color={C.magenta} onClick={() => setDamagePickerOpen(true)} rolling={rolling === 'D6'} last={lastRoll?.type === 'D6' ? lastRoll.value : null} />
          <DiceButton type="D20" label="Ação Rápida" color={C.cyan} onClick={() => rollDice('D20')} rolling={rolling === 'D20'} last={lastRoll?.type === 'D20' ? lastRoll.value : null} />
        </div>
      </div>

      {/* Modal: Dano Rápido — seletor de alvo */}
      {damagePickerOpen && (() => {
        const realPlayers = (shared.tablePlayers || []).filter(p => !(shared.kickedPlayers || []).includes(p.name));
        const summoned = (shared.summonedNPCs || []);
        return (
          <div onClick={() => setDamagePickerOpen(false)} style={{
            position: 'fixed', inset: 0,
            background: 'rgba(0,0,0,0.85)', zIndex: 100,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            padding: 18, animation: 'fade-in 0.2s',
          }}>
            <div onClick={e => e.stopPropagation()} className="clip-corner" style={{
              width: '100%', maxWidth: 360,
              background: C.bg2, border: `2px solid ${C.magenta}`,
              padding: 18,
            }}>
              <div className="mono" style={{ fontSize: 11, color: C.magenta, letterSpacing: '0.25em', marginBottom: 6 }}>
                // DANO RÁPIDO · D6
              </div>
              <div style={{ fontSize: 16, fontWeight: 700, color: C.text, marginBottom: 14 }}>
                Aplicar dano em:
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, maxHeight: 360, overflowY: 'auto' }}>
                {/* Jogadores reais */}
                {realPlayers.length > 0 && (
                  <div className="mono" style={{ fontSize: 9, color: C.textDim, letterSpacing: '0.2em', marginTop: 4 }}>
                    // JOGADORES
                  </div>
                )}
                {realPlayers.map(p => (
                  <button
                    key={p.name}
                    onClick={() => applyQuickDamage('player', p)}
                    className="clip-corner-sm"
                    style={{
                      background: C.bg3, border: `1px solid ${C.cyan}`,
                      borderLeft: `3px solid ${C.cyan}`,
                      color: C.text, padding: '10px 12px',
                      cursor: 'pointer', textAlign: 'left',
                      display: 'flex', alignItems: 'center', gap: 10,
                    }}
                  >
                    <div style={{
                      width: 28, height: 28, borderRadius: '50%',
                      background: C.cyan, color: '#000',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 14, fontWeight: 900, flexShrink: 0,
                    }}>◆</div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 13, fontWeight: 700 }}>{p.name}</div>
                      <div className="mono" style={{ fontSize: 9, color: C.textDim, letterSpacing: '0.15em' }}>
                        {(p.class || '').toUpperCase()} · HP {Number.isFinite(p.hp) ? p.hp : shared.playerHP}/{Number.isFinite(p.maxHp) ? p.maxHp : shared.playerMaxHP}
                      </div>
                    </div>
                  </button>
                ))}
                {/* NPCs invocados */}
                {summoned.length > 0 && (
                  <div className="mono" style={{ fontSize: 9, color: C.textDim, letterSpacing: '0.2em', marginTop: 6 }}>
                    // NPCs INVOCADOS
                  </div>
                )}
                {summoned.map(inst => {
                  const diff = getDifficulty(inst.diffId);
                  const isAlly = diff.type === 'ally';
                  const ac = isAlly ? '#00FF85' : diffSolidColor(diff);
                  const dead = (inst.hp || 0) <= 0;
                  return (
                    <button
                      key={inst.instanceId}
                      onClick={() => !dead && applyQuickDamage('npc', inst)}
                      disabled={dead}
                      className="clip-corner-sm"
                      style={{
                        background: C.bg3, border: `1px solid ${ac}`,
                        borderLeft: `3px solid ${ac}`,
                        color: C.text, padding: '10px 12px',
                        cursor: dead ? 'not-allowed' : 'pointer',
                        textAlign: 'left',
                        display: 'flex', alignItems: 'center', gap: 10,
                        opacity: dead ? 0.4 : 1,
                        textDecoration: dead ? 'line-through' : 'none',
                      }}
                    >
                      <div style={{
                        width: 28, height: 28, borderRadius: '50%',
                        background: C.bg2, border: `1.5px solid ${ac}`,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        flexShrink: 0,
                      }}>
                        <NPCSymbol diff={diff} size={16} isVendor={inst.isVendor} />
                      </div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontSize: 13, fontWeight: 700 }}>{inst.name}</div>
                        <div className="mono" style={{ fontSize: 9, color: C.textDim, letterSpacing: '0.15em' }}>
                          {isAlly ? 'ALIADO' : diff.label.toUpperCase()} · HP {inst.hp || 0}/{inst.maxHp || 0}
                        </div>
                      </div>
                    </button>
                  );
                })}
                {realPlayers.length === 0 && summoned.length === 0 && (
                  <div style={{
                    padding: 22, textAlign: 'center', color: C.textDim, fontSize: 12,
                    border: `1px dashed ${C.border}`,
                  }} className="clip-corner-sm">
                    Sem alvos disponíveis.<br/>Invoque NPCs ou aguarde um jogador entrar.
                  </div>
                )}
              </div>
              <button
                onClick={() => setDamagePickerOpen(false)}
                className="clip-corner-sm"
                style={{
                  width: '100%', marginTop: 14,
                  background: 'transparent', border: `1px solid ${C.border}`,
                  color: C.textDim, padding: '10px',
                  cursor: 'pointer', fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
                }}
              >CANCELAR</button>
            </div>
          </div>
        );
      })()}

      {/* Modal: Iniciativa */}
      {initiativeModal && (
        <div onClick={() => setInitiativeModal(null)} style={{
          position: 'fixed', inset: 0,
          background: 'rgba(0,0,0,0.85)', zIndex: 100,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          padding: 20, animation: 'fade-in 0.2s',
        }}>
          <div onClick={e => e.stopPropagation()} className="clip-corner" style={{
            width: '100%', maxWidth: 320,
            background: C.bg2, border: `2px solid ${C.cyan}`, padding: 18,
          }}>
            <div className="mono" style={{ fontSize: 10, color: C.cyan, letterSpacing: '0.3em', marginBottom: 4 }}>
              // INICIATIVA DO ATO
            </div>
            <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 14 }}>Ordem de ação</div>
            {initiativeModal.order.map((n, i) => (
              <div key={n} className="clip-corner-sm" style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                padding: '8px 12px', marginBottom: 6,
                background: C.bg3, border: `1px solid ${C.border}`, borderLeft: `3px solid ${C.cyan}`,
              }}>
                <div style={{ fontSize: 14, fontWeight: 600 }}>
                  <span style={{ color: C.cyan, marginRight: 8 }} className="mono">#{i + 1}</span>
                  {n}
                </div>
                <div className="mono" style={{ fontSize: 14, fontWeight: 700, color: C.yellow }}>
                  D20 · {initiativeModal.rolls[n]}
                </div>
              </div>
            ))}
            <div className="mono" style={{ fontSize: 9, color: C.textDim, letterSpacing: '0.15em', marginTop: 8, textAlign: 'center', fontStyle: 'italic' }}>
              // INIMIGOS SEMPRE POR ÚLTIMO
            </div>
            <button
              onClick={() => setInitiativeModal(null)}
              className="clip-corner-sm"
              style={{
                width: '100%', marginTop: 14,
                background: C.cyan, border: 'none', color: '#000',
                padding: '10px', cursor: 'pointer',
                fontWeight: 700, fontSize: 12, letterSpacing: '0.15em',
              }}
            >CONTINUAR</button>
          </div>
        </div>
      )}

      {/* Modal: Sem jogadores na cena */}
      {noPlayersAlert && (
        <div onClick={() => setNoPlayersAlert(false)} style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 100,
          display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24,
        }}>
          <div onClick={e => e.stopPropagation()} className="clip-corner" style={{
            width: '100%', maxWidth: 320,
            background: C.bg2, border: `2px solid ${C.magenta}`, padding: 18, textAlign: 'center',
          }}>
            <div className="mono" style={{ fontSize: 11, color: C.magenta, letterSpacing: '0.25em', marginBottom: 8 }}>
              // SEM JOGADORES NA CENA
            </div>
            <div style={{ fontSize: 13, color: C.text, lineHeight: 1.5, marginBottom: 16 }}>
              Combate exige ao menos um jogador conectado à mesa. Aguarde alguém entrar com o código antes de iniciar.
            </div>
            <button onClick={() => setNoPlayersAlert(false)} className="clip-corner-sm" style={{
              width: '100%', background: C.magenta, border: 'none', color: '#fff',
              padding: '10px', cursor: 'pointer', fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
            }}>ENTENDI</button>
          </div>
        </div>
      )}

      {/* Modal: Confirmar iniciar combate */}
      {confirmCombatStart && (
        <div onClick={() => setConfirmCombatStart(false)} style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 100,
          display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24,
        }}>
          <div onClick={e => e.stopPropagation()} className="clip-corner" style={{
            width: '100%', maxWidth: 320,
            background: C.bg2, border: `2px solid ${C.magenta}`, padding: 18, textAlign: 'center',
          }}>
            <div className="mono" style={{ fontSize: 11, color: C.magenta, letterSpacing: '0.25em', marginBottom: 8 }}>
              // INICIAR COMBATE?
            </div>
            <div style={{ fontSize: 13, color: C.text, lineHeight: 1.5, marginBottom: 16 }}>
              Jogadores agem na ordem da iniciativa, depois aliados, depois inimigos.
            </div>
            <div style={{ display: 'flex', gap: 8 }}>
              <button onClick={startCombat} className="clip-corner-sm" style={{
                flex: 1, background: C.magenta, border: 'none', color: '#fff',
                padding: '10px', cursor: 'pointer', fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
              }}>⚔ INICIAR</button>
              <button onClick={() => setConfirmCombatStart(false)} className="clip-corner-sm" style={{
                flex: 1, background: 'transparent', border: `1px solid ${C.border}`, color: C.textDim,
                padding: '10px', cursor: 'pointer', fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
              }}>CANCELAR</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Carregar aliados para a próxima cena? */}
      {carryConfirm && (() => {
        const destBase = (shared.sceneNPCs || {})[carryConfirm.newId] || [];
        const fits = destBase.length + carryConfirm.allies.length <= MAX_SCENE_NPCS;
        return (
          <div onClick={() => setCarryConfirm(null)} style={{
            position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 100,
            display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24,
          }}>
            <div onClick={e => e.stopPropagation()} className="clip-corner" style={{
              width: '100%', maxWidth: 340,
              background: C.bg2, border: `2px solid ${C.cyan}`, padding: 18, textAlign: 'center',
            }}>
              <div className="mono" style={{ fontSize: 11, color: C.cyan, letterSpacing: '0.25em', marginBottom: 8 }}>
                // CARREGAR ALIADOS?
              </div>
              <div style={{ fontSize: 13, color: C.text, lineHeight: 1.5, marginBottom: 12 }}>
                {carryConfirm.allies.length} aliado(s) em cena. Levar para o Ato {String(carryConfirm.newId).padStart(2,'0')}?
              </div>
              <div className="mono" style={{ fontSize: 10, color: C.textDim, letterSpacing: '0.15em', marginBottom: 14 }}>
                {carryConfirm.allies.map(a => a.name).join(' · ')}
              </div>
              {!fits && (
                <div className="mono" style={{ fontSize: 10, color: C.magenta, letterSpacing: '0.15em', marginBottom: 14 }}>
                  ⚠ ATO DESTINO LOTADO ({destBase.length}/{MAX_SCENE_NPCS}) — SEM ESPAÇO PARA {carryConfirm.allies.length}
                </div>
              )}
              <div style={{ display: 'flex', gap: 8 }}>
                <button
                  onClick={() => goToPoint(carryConfirm.newId, true)}
                  disabled={!fits}
                  className="clip-corner-sm"
                  style={{
                    flex: 1, background: fits ? C.cyan : C.bg3, border: 'none', color: fits ? '#000' : C.textDim,
                    padding: '10px', cursor: fits ? 'pointer' : 'not-allowed',
                    fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
                    opacity: fits ? 1 : 0.5,
                  }}>CARREGAR</button>
                <button
                  onClick={() => goToPoint(carryConfirm.newId, false)}
                  className="clip-corner-sm"
                  style={{
                    flex: 1, background: 'transparent', border: `1px solid ${C.border}`, color: C.textDim,
                    padding: '10px', cursor: 'pointer', fontWeight: 700, fontSize: 12, letterSpacing: '0.1em',
                  }}>DEIXAR</button>
              </div>
              <button
                onClick={() => setCarryConfirm(null)}
                style={{
                  background: 'transparent', border: 'none', color: C.textDim,
                  padding: '8px 0 0', cursor: 'pointer', fontSize: 11, letterSpacing: '0.15em',
                  width: '100%',
                }}>cancelar</button>
            </div>
          </div>
        );
      })()}

      {/* Desafio de grupo — abre tela dedicada */}
      <div style={{ padding: '8px 16px' }}>
        <button
          onClick={() => {
            if (onlinePlayerNames.length === 0) {
              showToast('NENHUM JOGADOR ONLINE NA MESA', C.magenta);
              return;
            }
            onNav('master-challenges');
          }}
          className="clip-corner"
          style={{
            width: '100%',
            background: `linear-gradient(135deg, ${C.bg2} 0%, ${C.bg3} 100%)`,
            border: `2px solid ${C.green}`,
            color: C.text,
            padding: '14px 16px',
            cursor: 'pointer',
            textAlign: 'left',
            display: 'flex',
            alignItems: 'center',
            gap: 14,
          }}
        >
          <div style={{ fontSize: 28, color: C.green }}>⌬</div>
          <div style={{ flex: 1 }}>
            <div className="mono" style={{ fontSize: 10, color: C.green, letterSpacing: '0.2em' }}>DESAFIO DE GRUPO</div>
            <div style={{ fontSize: 15, fontWeight: 700 }}>Enviar Desafios de Grupo</div>
            <div style={{ fontSize: 11, color: C.textDim }}>
              {CHALLENGE_CATALOG.length} desafios disponíveis · Fácil/Normal/Difícil
            </div>
          </div>
          <div style={{ color: C.green, fontSize: 18 }}>▶</div>
        </button>
      </div>

      {/* Ações */}
      <div style={{ padding: 16 }}>
        <div className="mono" style={{ color: C.textDim, fontSize: 10, letterSpacing: '0.2em', marginBottom: 10 }}>
          // CONTROLE DA MESA
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          <ActionRow icon="◆" label="Seus Jogadores" desc="Vantagens, desafios particulares e chat" onClick={() => onNav('master-players')} color={C.cyan} />
          <ActionRow icon="✺" label="Seus NPCs" desc={`${shared.savedNPCs.length}/${MAX_SAVED_NPCS} cadastrados · ${shared.summonedNPCs.length}/${MAX_SCENE_NPCS} em cena`} onClick={() => onNav('master-npcs')} color={C.magenta} />
          <ActionRow
            icon="⌂"
            label={shared.activeShop ? `Loja Ativa · ${shared.activeShop.vendor}` : 'Invocar Loja'}
            desc={shared.activeShop
              ? `${shared.activeShop.rarityLabel} · ${shared.activeShop.items.length} itens · tocar para fechar`
              : 'Gera vendedor aleatório com itens por raridade'}
            onClick={() => setShopPickerOpen(true)}
            color={shared.activeShop ? shared.activeShop.rarityColor : C.yellow}
          />
        </div>
      </div>

      {shopPickerOpen && (
        <ShopPickerModal
          activeShop={shared.activeShop}
          onPick={(rarityId) => { openShopWithRarity(rarityId); setShopPickerOpen(false); }}
          onClose={() => setShopPickerOpen(false)}
          onCloseShop={closeActiveShop}
        />
      )}
    </div>
  );
};

const DiceButton = ({ type, label, color, onClick, rolling, last }) => (
  <button onClick={onClick} disabled={rolling} className="clip-corner" style={{
    background: C.bg2,
    border: `2px solid ${color}`,
    padding: '16px 8px',
    cursor: 'pointer',
    color: C.text,
    position: 'relative',
    overflow: 'hidden',
    minHeight: 110,
  }}>
    <div style={{
      fontSize: type === '★' ? 32 : 26,
      fontWeight: 700,
      color: color,
      animation: rolling ? 'dice-spin 0.8s ease' : 'none',
      letterSpacing: '-0.02em',
    }} className="mono">
      {rolling ? '??' : (last !== null ? last : type)}
    </div>
    <div style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.15em', textTransform: 'uppercase', marginTop: 4 }} className="mono">
      {label}
    </div>
    {last !== null && !rolling && (
      <div className="mono" style={{ fontSize: 9, color: color, marginTop: 4, letterSpacing: '0.1em' }}>
        {type}
      </div>
    )}
  </button>
);

const ActionRow = ({ icon, label, desc, onClick, color }) => (
  <button onClick={onClick} className="clip-corner-sm" style={{
    background: C.bg2,
    border: `1px solid ${C.border}`,
    borderLeft: `3px solid ${color}`,
    padding: '14px 16px',
    cursor: 'pointer',
    color: C.text,
    textAlign: 'left',
    display: 'flex',
    alignItems: 'center',
    gap: 14,
  }}>
    <div style={{ fontSize: 22, color }}>{icon}</div>
    <div style={{ flex: 1 }}>
      <div style={{ fontSize: 15, fontWeight: 600 }}>{label}</div>
      <div style={{ fontSize: 12, color: C.textDim }}>{desc}</div>
    </div>
    <div style={{ color: color, fontSize: 18 }}>→</div>
  </button>
);

