// ============== DESAFIOS DE GRUPO (minigames) ==============
// Dificuldades aplicadas aos minigames. Quanto maior, menos tempo / maior chance de erro da IA.
const CHALLENGE_DIFFS = [
  // timeMult com folga: a maioria dos desafios não é importante fazer com pressa.
  { id: 'easy',   label: 'Fácil',   color: '#00FF85', timeMult: 2.0, aiSuccess: 0.92 },
  { id: 'normal', label: 'Normal',  color: '#FCEE0A', timeMult: 1.5, aiSuccess: 0.75 },
  { id: 'hard',   label: 'Difícil', color: '#FF003C', timeMult: 1.0, aiSuccess: 0.45 },
];
const getChalDiff = (id) => CHALLENGE_DIFFS.find(d => d.id === id) || CHALLENGE_DIFFS[1];

const CHALLENGE_CATALOG = [
  { id: 'reflex',     name: 'Astúcia',      desc: 'Pedra · Papel · Tesoura',     icon: '✦', color: '#FF003C' },
  { id: 'force',      name: 'Resistência',  desc: 'Cliques repetitivos',          icon: '⚒', color: '#00FF85' },
  { id: 'lockpick',   name: 'Arrombamento', desc: '4 fechaduras em sequência',    icon: '⌬', color: '#FCEE0A' },
  { id: 'perception', name: 'Percepção',    desc: 'Memorizar um código',          icon: '◉', color: '#00F0FF' },
  { id: 'hack',       name: 'Hacking',      desc: 'Jogo da velha vs sistema',     icon: '⌬', color: '#00FF85' },
  { id: 'romance',    name: 'Romance',      desc: 'Roleta do amor · 50/50',       icon: '♥', color: '#FF3FB4' },
  { id: 'persuasion', name: 'Persuasão',    desc: 'Escolha o argumento certo',    icon: '✦', color: '#B026FF' },
  { id: 'stealth',    name: 'Furtividade',  desc: 'Pare na zona segura',          icon: '◈', color: '#00F0FF' },
  { id: 'survival',   name: 'Sobrevivência', desc: 'Pesque o recurso certo',      icon: '⌬', color: '#FF8A00' },
  { id: 'coinflip',   name: 'Diplomacia',   desc: 'Cara ou coroa',                icon: '◯', color: '#FCEE0A' },
];

// ----- Reflexo: Pedra-Papel-Tesoura -----
const MGReflex = ({ diff, onResolve, manual }) => {
  const RPS = [
    { id: 'rock',     label: 'PEDRA',   icon: '✊' },
    { id: 'paper',    label: 'PAPEL',   icon: '✋' },
    { id: 'scissors', label: 'TESOURA', icon: '✌' },
  ];
  const beats = { rock: 'scissors', paper: 'rock', scissors: 'paper' };
  const [sysPick] = useState(() => RPS[Math.floor(Math.random() * 3)]);
  const [userPick, setUserPick] = useState(null);
  const [reveal, setReveal] = useState(false);
  const totalMs = Math.round(4000 * diff.timeMult);
  const [timeLeft, setTimeLeft] = useState(totalMs);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);

  // Timer pro modo manual (estoura → falha)
  useEffect(() => {
    if (!manual) return;
    const id = setInterval(() => {
      const remaining = Math.max(0, totalMs - (Date.now() - startRef.current));
      setTimeLeft(remaining);
      if (remaining <= 0) {
        clearInterval(id);
        if (!resolvedRef.current && !userPick) {
          resolvedRef.current = true;
          onResolve(false, `Tempo esgotado · SISTEMA: ${sysPick.label}`);
        }
      }
    }, 100);
    return () => clearInterval(id);
  }, [manual]);

  // Modo IA: escolha automática
  useEffect(() => {
    if (manual) return;
    const aiDelay = 500 + Math.random() * 900;
    const t = setTimeout(() => {
      const winChoice = Object.keys(beats).find(k => beats[k] === sysPick.id);
      let chosenId;
      if (Math.random() < diff.aiSuccess) {
        chosenId = winChoice;
      } else {
        chosenId = Math.random() < 0.5 ? sysPick.id : beats[sysPick.id];
      }
      setUserPick(RPS.find(r => r.id === chosenId));
      setTimeout(() => setReveal(true), 350);
    }, aiDelay);
    return () => clearTimeout(t);
  }, [manual]);

  useEffect(() => {
    if (!reveal || !userPick || resolvedRef.current) return;
    const t = setTimeout(() => {
      resolvedRef.current = true;
      const success = beats[userPick.id] === sysPick.id;
      const who = manual ? 'VOCÊ' : 'IA';
      onResolve(success, `${who}: ${userPick.label} vs SISTEMA: ${sysPick.label}`);
    }, 800);
    return () => clearTimeout(t);
  }, [reveal]);

  const pickManual = (opt) => {
    if (!manual || userPick) return;
    setUserPick(opt);
    setTimeout(() => setReveal(true), 250);
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 12 }}>
        // ESCOLHA O CONTRA-ATAQUE {manual ? `· ${(timeLeft/1000).toFixed(1)}s` : ''}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 10, marginBottom: 22 }}>
        {RPS.map(opt => {
          const isPicked = userPick && userPick.id === opt.id;
          const clickable = manual && !userPick;
          return (
            <button
              key={opt.id}
              onClick={() => pickManual(opt)}
              disabled={!clickable}
              className="clip-corner-sm"
              style={{
                background: isPicked ? `${diff.color}33` : C.bg2,
                border: `2px solid ${isPicked ? diff.color : C.border}`,
                padding: '18px 6px',
                textAlign: 'center',
                cursor: clickable ? 'pointer' : 'default',
                transition: 'all 0.2s',
                color: 'inherit',
              }}
            >
              <div style={{ fontSize: 32 }}>{opt.icon}</div>
              <div className="mono" style={{ fontSize: 10, letterSpacing: '0.2em', marginTop: 4, color: isPicked ? diff.color : C.textDim }}>
                {opt.label}
              </div>
            </button>
          );
        })}
      </div>
      <div className="mono" style={{ fontSize: 10, color: C.textDim, letterSpacing: '0.2em', marginBottom: 6 }}>
        // SISTEMA
      </div>
      <div style={{
        fontSize: 48,
        opacity: reveal ? 1 : 0.15,
        filter: reveal ? 'none' : 'blur(6px)',
        transition: 'all 0.3s',
      }}>{sysPick.icon}</div>
    </div>
  );
};

// ----- Força: Cliques repetitivos -----
const MGForce = ({ diff, onResolve, manual }) => {
  const target = 30;
  const totalMs = Math.round(4500 * diff.timeMult);
  const [clicks, setClicks] = useState(0);
  const [timeLeft, setTimeLeft] = useState(totalMs);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);

  // IA: auto-clica
  useEffect(() => {
    if (manual) return;
    const baseInterval = 120 + (1 - diff.aiSuccess) * 180;
    const jitter = () => baseInterval * (0.75 + Math.random() * 0.5);
    let timer;
    const tick = () => {
      setClicks(c => (c >= target ? c : c + 1));
      timer = setTimeout(tick, jitter());
    };
    timer = setTimeout(tick, jitter());
    return () => clearTimeout(timer);
  }, [manual]);

  useEffect(() => {
    const id = setInterval(() => {
      const remaining = Math.max(0, totalMs - (Date.now() - startRef.current));
      setTimeLeft(remaining);
      if (remaining <= 0) clearInterval(id);
    }, 80);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    if (resolvedRef.current) return;
    if (clicks >= target) {
      resolvedRef.current = true;
      onResolve(true, `${clicks}/${target} cliques`);
    } else if (timeLeft <= 0) {
      resolvedRef.current = true;
      onResolve(false, `${clicks}/${target} cliques`);
    }
  }, [clicks, timeLeft]);

  const pct = Math.min(100, (clicks / target) * 100);
  const secs = (timeLeft / 1000).toFixed(1);

  const hit = () => {
    if (!manual) return;
    setClicks(c => (c >= target ? c : c + 1));
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 14 }}>
        // MARTELE ATÉ ENCHER · {secs}s
      </div>
      <div style={{ height: 22, background: C.bg2, border: `1px solid ${C.border}`, marginBottom: 18, position: 'relative', overflow: 'hidden' }}>
        <div style={{
          position: 'absolute', inset: 0,
          width: `${pct}%`,
          background: `linear-gradient(90deg, ${diff.color}, #FFF)`,
          transition: 'width 0.1s linear',
          boxShadow: `0 0 12px ${diff.color}`,
        }} />
        <div className="mono" style={{
          position: 'absolute', inset: 0,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          color: '#000', fontWeight: 700, fontSize: 12, letterSpacing: '0.2em',
          mixBlendMode: 'difference',
        }}>{clicks}/{target}</div>
      </div>
      <button
        onClick={hit}
        disabled={!manual}
        style={{
          width: 130, height: 130, borderRadius: '50%',
          background: C.bg2, border: `3px solid ${diff.color}`,
          margin: '0 auto', display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 56, color: diff.color, fontWeight: 900,
          transform: `scale(${1 - (clicks % 2) * 0.05})`,
          transition: 'transform 0.06s',
          boxShadow: `0 0 24px ${diff.color}66`,
          cursor: manual ? 'pointer' : 'default',
          padding: 0,
        }}
      >⚒</button>
    </div>
  );
};

// ----- Arrombamento: Sequência tipo Simon (4 fechaduras) -----
const MGLockpick = ({ diff, onResolve, manual }) => {
  const length = diff.id === 'easy' ? 3 : diff.id === 'hard' ? 5 : 4;
  const [seq] = useState(() => Array.from({ length }, () => Math.floor(Math.random() * 4)));
  const [phase, setPhase] = useState('show');
  const [showIdx, setShowIdx] = useState(-1);
  const [inputIdx, setInputIdx] = useState(0);
  const [active, setActive] = useState(-1);
  const [failed, setFailed] = useState(false);
  const resolvedRef = useRef(false);

  // Fase 1: mostrar sequência (para ambos os modos)
  useEffect(() => {
    if (phase !== 'show') return;
    let i = 0;
    const flash = () => {
      if (i >= seq.length) {
        setShowIdx(-1);
        setTimeout(() => setPhase('input'), 400);
        return;
      }
      setShowIdx(seq[i]);
      setTimeout(() => { setShowIdx(-1); i++; setTimeout(flash, 200); }, 500);
    };
    const t = setTimeout(flash, 600);
    return () => clearTimeout(t);
  }, [phase]);

  // Fase 2 (IA): repete automaticamente
  useEffect(() => {
    if (manual || phase !== 'input' || resolvedRef.current) return;
    if (inputIdx >= seq.length) {
      resolvedRef.current = true;
      onResolve(true, `Sequência de ${seq.length}`);
      return;
    }
    const t = setTimeout(() => {
      const perTap = Math.pow(diff.aiSuccess, 1 / seq.length);
      const correct = Math.random() < perTap;
      const tapped = correct ? seq[inputIdx] : (seq[inputIdx] + 1 + Math.floor(Math.random() * 3)) % 4;
      setActive(tapped);
      setTimeout(() => {
        setActive(-1);
        if (!correct) {
          setFailed(true);
          resolvedRef.current = true;
          setTimeout(() => onResolve(false, `Errou no toque ${inputIdx + 1}`), 600);
        } else {
          setInputIdx(i => i + 1);
        }
      }, 280);
    }, 480);
    return () => clearTimeout(t);
  }, [phase, inputIdx, manual]);

  // Manual: aguarda input do jogador
  const onTapLock = (i) => {
    if (!manual || phase !== 'input' || resolvedRef.current || failed) return;
    setActive(i);
    setTimeout(() => setActive(-1), 250);
    if (seq[inputIdx] === i) {
      const next = inputIdx + 1;
      setInputIdx(next);
      if (next >= seq.length) {
        resolvedRef.current = true;
        setTimeout(() => onResolve(true, `Sequência de ${seq.length}`), 400);
      }
    } else {
      setFailed(true);
      resolvedRef.current = true;
      setTimeout(() => onResolve(false, `Errou no toque ${inputIdx + 1}`), 600);
    }
  };

  const locks = [0, 1, 2, 3];
  const clickable = manual && phase === 'input' && !failed && !resolvedRef.current;
  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 14 }}>
        // {phase === 'show' ? 'MEMORIZE A SEQUÊNCIA' : phase === 'input' ? (manual ? 'REPITA A SEQUÊNCIA' : 'REPETINDO...') : 'CONCLUÍDO'} · {inputIdx}/{seq.length}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 12, maxWidth: 260, margin: '0 auto' }}>
        {locks.map(i => {
          const lit = showIdx === i || active === i;
          return (
            <button
              key={i}
              onClick={() => onTapLock(i)}
              disabled={!clickable}
              className="clip-corner-sm"
              style={{
                aspectRatio: '1 / 1',
                background: lit ? (failed ? C.magenta : diff.color) : C.bg2,
                border: `2px solid ${lit ? (failed ? C.magenta : diff.color) : C.border}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 36, color: lit ? '#000' : C.textDim,
                fontWeight: 900,
                transition: 'all 0.15s',
                boxShadow: lit ? `0 0 22px ${failed ? C.magenta : diff.color}` : 'none',
                cursor: clickable ? 'pointer' : 'default',
                padding: 0,
              }}
            >⌬</button>
          );
        })}
      </div>
    </div>
  );
};

// ----- Percepção: Memorizar dígitos -----
const MGPerception = ({ diff, onResolve, manual }) => {
  const length = diff.id === 'easy' ? 3 : diff.id === 'hard' ? 5 : 4;
  const showMs = Math.round(2000 * diff.timeMult);
  const [code] = useState(() => Array.from({ length }, () => Math.floor(Math.random() * 10)).join(''));
  const [phase, setPhase] = useState('show');
  const [typed, setTyped] = useState('');
  const resolvedRef = useRef(false);

  useEffect(() => {
    if (phase !== 'show') return;
    const t = setTimeout(() => setPhase('input'), showMs);
    return () => clearTimeout(t);
  }, [phase]);

  // Resolve quando preencheu todos os dígitos
  useEffect(() => {
    if (phase !== 'input' || typed.length < length || resolvedRef.current) return;
    resolvedRef.current = true;
    const success = typed === code;
    const t = setTimeout(() => onResolve(success, `Código: ${code} · Digitou: ${typed}`), 500);
    return () => clearTimeout(t);
  }, [typed, phase]);

  // IA: digita automaticamente
  useEffect(() => {
    if (manual || phase !== 'input' || resolvedRef.current) return;
    if (typed.length >= length) return;
    const t = setTimeout(() => {
      const perDigit = Math.pow(diff.aiSuccess, 1 / length);
      const correct = Math.random() < perDigit;
      const digit = correct ? code[typed.length] : String(Math.floor(Math.random() * 10));
      setTyped(s => s + digit);
    }, 350);
    return () => clearTimeout(t);
  }, [phase, typed, manual]);

  const tapDigit = (d) => {
    if (!manual || phase !== 'input' || typed.length >= length || resolvedRef.current) return;
    setTyped(s => s + String(d));
  };

  const clear = () => {
    if (!manual || resolvedRef.current) return;
    setTyped('');
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 18 }}>
        // {phase === 'show' ? 'MEMORIZE O CÓDIGO' : (manual ? 'DIGITE O CÓDIGO' : 'DIGITANDO...')}
      </div>
      <div style={{
        display: 'flex', justifyContent: 'center', gap: 10,
        marginBottom: 14,
        minHeight: 88,
      }}>
        {[...code].map((d, i) => (
          <div key={i} className="clip-corner-sm" style={{
            width: 52, height: 72,
            background: C.bg2,
            border: `2px solid ${phase === 'show' ? diff.color : (typed[i] ? (typed[i] === d ? diff.color : C.magenta) : C.border)}`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 38, fontWeight: 900,
            color: phase === 'show' ? diff.color : (typed[i] || phase === 'input' ? C.text : C.textDim),
            fontFamily: 'JetBrains Mono, monospace',
            boxShadow: phase === 'show' ? `0 0 14px ${diff.color}66` : 'none',
          }}>
            {phase === 'show' ? d : (typed[i] || '_')}
          </div>
        ))}
      </div>

      {/* Keypad (modo manual) */}
      {manual && phase === 'input' && (
        <div style={{
          display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 6,
          maxWidth: 260, margin: '0 auto',
        }}>
          {[1,2,3,4,5,6,7,8,9].map(d => (
            <button
              key={d}
              onClick={() => tapDigit(d)}
              className="clip-corner-sm"
              style={{
                background: C.bg2, border: `1px solid ${diff.color}`,
                color: diff.color, padding: '12px 0',
                fontSize: 22, fontWeight: 900,
                fontFamily: 'JetBrains Mono, monospace',
                cursor: 'pointer',
              }}
            >{d}</button>
          ))}
          <button onClick={clear} className="clip-corner-sm" style={{
            background: C.bg2, border: `1px solid ${C.border}`,
            color: C.textDim, padding: '12px 0', fontSize: 12, letterSpacing: '0.1em',
            cursor: 'pointer', fontWeight: 700,
          }}>LIMPAR</button>
          <button onClick={() => tapDigit(0)} className="clip-corner-sm" style={{
            background: C.bg2, border: `1px solid ${diff.color}`,
            color: diff.color, padding: '12px 0',
            fontSize: 22, fontWeight: 900,
            fontFamily: 'JetBrains Mono, monospace',
            cursor: 'pointer',
          }}>0</button>
          <div />
        </div>
      )}
    </div>
  );
};

// ----- Hacking: jogo da velha vs IA -----
const MGHack = ({ diff, onResolve, manual }) => {
  const [board, setBoard] = useState(Array(9).fill(null)); // 'X' (jogador), 'O' (IA)
  const [turn, setTurn] = useState('X');
  const resolvedRef = useRef(false);

  const winLines = [[0,1,2],[3,4,5],[6,7,8],[0,3,6],[1,4,7],[2,5,8],[0,4,8],[2,4,6]];
  const checkWin = (b) => {
    for (const [a,c,d] of winLines) if (b[a] && b[a] === b[c] && b[a] === b[d]) return b[a];
    return null;
  };

  const resolveFinal = (b) => {
    if (resolvedRef.current) return;
    const w = checkWin(b);
    if (w === 'X') { resolvedRef.current = true; setTimeout(() => onResolve(true, 'Hack bem-sucedido'), 400); }
    else if (w === 'O') { resolvedRef.current = true; setTimeout(() => onResolve(false, 'Sistema venceu'), 400); }
    else if (b.every(x => x)) { resolvedRef.current = true; setTimeout(() => onResolve(true, 'Empate · hack passou'), 400); }
  };

  // IA escolhe jogada (preferência: vencer > bloquear > centro > canto > random)
  const aiMove = (b) => {
    const empty = b.map((v,i) => v ? null : i).filter(i => i !== null);
    if (!empty.length) return null;
    // Tenta vencer
    for (const i of empty) { const t = [...b]; t[i] = 'O'; if (checkWin(t) === 'O') return i; }
    // Bloqueia X
    if (Math.random() < diff.aiSuccess) {
      for (const i of empty) { const t = [...b]; t[i] = 'X'; if (checkWin(t) === 'X') return i; }
    }
    // Centro
    if (empty.includes(4) && Math.random() < diff.aiSuccess) return 4;
    // Canto
    const corners = [0,2,6,8].filter(c => empty.includes(c));
    if (corners.length && Math.random() < diff.aiSuccess * 0.7) return corners[Math.floor(Math.random()*corners.length)];
    return empty[Math.floor(Math.random()*empty.length)];
  };

  // IA joga quando turn === 'O'
  useEffect(() => {
    if (resolvedRef.current) return;
    if (turn !== 'O') return;
    const t = setTimeout(() => {
      const idx = aiMove(board);
      if (idx === null) { resolveFinal(board); return; }
      const next = [...board];
      next[idx] = 'O';
      setBoard(next);
      const w = checkWin(next);
      if (w || next.every(x => x)) { resolveFinal(next); }
      else setTurn('X');
    }, 550);
    return () => clearTimeout(t);
  }, [turn]);

  // Modo IA (sem jogador real): "X" também é IA aleatória
  useEffect(() => {
    if (manual) return;
    if (resolvedRef.current) return;
    if (turn !== 'X') return;
    const t = setTimeout(() => {
      const empty = board.map((v,i) => v ? null : i).filter(i => i !== null);
      if (!empty.length) { resolveFinal(board); return; }
      // X auto-joga com bias por aiSuccess (chance de jogada "boa")
      let idx;
      if (Math.random() < diff.aiSuccess) {
        // Tenta vencer com X
        let pick = null;
        for (const i of empty) { const t2 = [...board]; t2[i] = 'X'; if (checkWin(t2) === 'X') { pick = i; break; } }
        idx = pick !== null ? pick : empty[Math.floor(Math.random()*empty.length)];
      } else {
        idx = empty[Math.floor(Math.random()*empty.length)];
      }
      const next = [...board];
      next[idx] = 'X';
      setBoard(next);
      const w = checkWin(next);
      if (w || next.every(x => x)) { resolveFinal(next); }
      else setTurn('O');
    }, 500);
    return () => clearTimeout(t);
  }, [turn, manual]);

  const tapCell = (i) => {
    if (!manual || resolvedRef.current || board[i] || turn !== 'X') return;
    const next = [...board];
    next[i] = 'X';
    setBoard(next);
    const w = checkWin(next);
    if (w || next.every(x => x)) { resolveFinal(next); }
    else setTurn('O');
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 14 }}>
        // {turn === 'X' ? (manual ? 'SUA VEZ (X)' : 'JOGADOR JOGANDO...') : 'SISTEMA JOGANDO...'}
      </div>
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(3, 1fr)',
        gap: 6,
        maxWidth: 240, margin: '0 auto',
      }}>
        {board.map((cell, i) => {
          const clickable = manual && !cell && turn === 'X' && !resolvedRef.current;
          return (
            <button
              key={i}
              onClick={() => tapCell(i)}
              disabled={!clickable}
              className="clip-corner-sm"
              style={{
                aspectRatio: '1 / 1',
                background: C.bg2,
                border: `2px solid ${cell === 'X' ? C.cyan : cell === 'O' ? C.magenta : C.border}`,
                color: cell === 'X' ? C.cyan : C.magenta,
                fontSize: 40, fontWeight: 900,
                fontFamily: 'JetBrains Mono, monospace',
                cursor: clickable ? 'pointer' : 'default',
                padding: 0,
              }}
            >{cell || ''}</button>
          );
        })}
      </div>
      <div className="mono" style={{ marginTop: 14, fontSize: 10, color: C.textDim, letterSpacing: '0.2em' }}>
        VOCÊ = <span style={{ color: C.cyan }}>X</span> · SISTEMA = <span style={{ color: C.magenta }}>O</span>
      </div>
    </div>
  );
};

// ----- Romance: Roleta do amor (50/50 com tempo) -----
const MGRomance = ({ diff, onResolve, manual }) => {
  const totalMs = Math.round(4000 * diff.timeMult);
  const [angle, setAngle] = useState(0);
  const [stopped, setStopped] = useState(false);
  const [result, setResult] = useState(null);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);
  const SECTORS = 8; // 4 verdes (win) e 4 vermelhos (lose) alternando
  const SECTOR_DEG = 360 / SECTORS;

  // Animação contínua (gira rápido até parar)
  useEffect(() => {
    if (stopped) return;
    let raf;
    const tick = () => {
      setAngle(a => (a + 6) % 360);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [stopped]);

  // Timer pra manual (estoura → falha)
  useEffect(() => {
    if (!manual) return;
    const id = setInterval(() => {
      if (Date.now() - startRef.current >= totalMs && !resolvedRef.current) {
        clearInterval(id);
        resolvedRef.current = true;
        onResolve(false, 'Hesitação fatal · sem decisão');
      }
    }, 200);
    return () => clearInterval(id);
  }, [manual, totalMs, onResolve]);

  // IA: auto-stop com viés pela dificuldade
  useEffect(() => {
    if (manual) return;
    const aiDelay = 800 + Math.random() * 1400;
    const t = setTimeout(() => doStop(Math.random() < diff.aiSuccess), aiDelay);
    return () => clearTimeout(t);
  }, [manual]);

  const doStop = (forceWin) => {
    if (stopped) return;
    setStopped(true);
    // Se forçar vitória, escolhemos um setor par (verde)
    const finalSector = forceWin === true ? Math.floor(Math.random() * (SECTORS / 2)) * 2
      : forceWin === false ? Math.floor(Math.random() * (SECTORS / 2)) * 2 + 1
      : Math.floor(Math.random() * SECTORS);
    const finalAngle = finalSector * SECTOR_DEG + SECTOR_DEG / 2;
    setAngle(finalAngle);
    const win = finalSector % 2 === 0;
    setResult(win);
    setTimeout(() => {
      if (resolvedRef.current) return;
      resolvedRef.current = true;
      onResolve(win, win ? 'Coração conquistado' : 'Rejeição cruel');
    }, 1200);
  };

  const sectors = Array.from({ length: SECTORS }, (_, i) => ({
    color: i % 2 === 0 ? '#FF3FB4' : '#7a1d3a',
    angle: i * SECTOR_DEG,
  }));

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 14 }}>
        // RODA DO AMOR · {manual ? 'TOQUE PRA PARAR' : 'IA DECIDINDO'}
      </div>
      <div style={{ position: 'relative', width: 200, height: 200, margin: '0 auto 16px' }}>
        <div style={{
          position: 'absolute', inset: 0, borderRadius: '50%',
          background: `conic-gradient(${sectors.map((s, i) => `${s.color} ${s.angle}deg ${s.angle + SECTOR_DEG}deg`).join(', ')})`,
          transform: `rotate(${angle}deg)`,
          transition: stopped ? 'transform 0.8s cubic-bezier(0.25,0.46,0.45,0.94)' : 'none',
          boxShadow: `0 0 20px ${diff.color}66`,
        }} />
        {/* Indicador fixo no topo */}
        <div style={{
          position: 'absolute', top: -8, left: '50%', transform: 'translateX(-50%)',
          width: 0, height: 0,
          borderLeft: '12px solid transparent', borderRight: '12px solid transparent',
          borderTop: `18px solid ${C.yellow}`, filter: `drop-shadow(0 0 6px ${C.yellow})`,
        }} />
        <div style={{
          position: 'absolute', inset: '40%', borderRadius: '50%',
          background: C.bg, border: `2px solid ${C.text}`,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 24, color: '#FF3FB4',
        }}>♥</div>
      </div>
      {manual && !stopped && (
        <button onClick={() => doStop()} className="clip-corner-sm" style={{
          background: diff.color, border: 'none', color: '#000',
          padding: '12px 32px', cursor: 'pointer', fontWeight: 900,
          fontSize: 14, letterSpacing: '0.2em',
        }}>PARAR</button>
      )}
      {result !== null && (
        <div className="mono" style={{
          fontSize: 14, color: result ? '#FF3FB4' : '#FF003C',
          letterSpacing: '0.3em', fontWeight: 900, marginTop: 8,
          animation: 'reveal-pop 0.5s cubic-bezier(0.34,1.56,0.64,1)',
        }}>{result ? '♥ AMOR ♥' : 'REJEITADO'}</div>
      )}
    </div>
  );
};

// ----- Persuasão: escolher o argumento correto entre 4 opções -----
const MGPersuasion = ({ diff, onResolve, manual }) => {
  const ARGS = [
    'Apelo Emocional', 'Lógica Fria', 'Ameaça Velada', 'Bajulação',
    'Chantagem', 'Verdade Crua', 'Mistério', 'Provocação',
  ];
  const [pool] = useState(() => [...ARGS].sort(() => Math.random() - 0.5).slice(0, 4));
  const [correct] = useState(() => Math.floor(Math.random() * 4));
  const [pick, setPick] = useState(null);
  const totalMs = Math.round(5000 * diff.timeMult);
  const [timeLeft, setTimeLeft] = useState(totalMs);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);

  useEffect(() => {
    if (!manual) return;
    const id = setInterval(() => {
      const r = Math.max(0, totalMs - (Date.now() - startRef.current));
      setTimeLeft(r);
      if (r <= 0 && !resolvedRef.current && pick === null) {
        clearInterval(id);
        resolvedRef.current = true;
        onResolve(false, 'Silêncio · perdeu a janela');
      }
    }, 100);
    return () => clearInterval(id);
  }, [manual]);

  useEffect(() => {
    if (manual) return;
    const t = setTimeout(() => {
      const idx = Math.random() < diff.aiSuccess ? correct : Math.floor(Math.random() * 4);
      pickArg(idx);
    }, 700 + Math.random() * 1100);
    return () => clearTimeout(t);
  }, [manual]);

  const pickArg = (i) => {
    if (pick !== null) return;
    setPick(i);
    setTimeout(() => {
      if (resolvedRef.current) return;
      resolvedRef.current = true;
      const ok = i === correct;
      onResolve(ok, ok ? `Escolheu "${pool[i]}" e convenceu` : `Escolheu "${pool[i]}" e fracassou (era "${pool[correct]}")`);
    }, 700);
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 12 }}>
        // ESCOLHA O ARGUMENTO {manual ? `· ${(timeLeft/1000).toFixed(1)}s` : '· IA'}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginBottom: 12 }}>
        {pool.map((arg, i) => {
          const isPick = pick === i;
          const showResult = pick !== null;
          const isRight = showResult && i === correct;
          const bg = showResult ? (isRight ? '#00FF8533' : isPick ? '#FF003C33' : C.bg2) : (isPick ? `${diff.color}33` : C.bg2);
          const bc = showResult ? (isRight ? '#00FF85' : isPick ? '#FF003C' : C.border) : (isPick ? diff.color : C.border);
          return (
            <button
              key={i}
              onClick={() => manual && pickArg(i)}
              disabled={!manual || pick !== null}
              className="clip-corner-sm"
              style={{
                background: bg, border: `1.5px solid ${bc}`,
                color: C.text, padding: '14px 8px',
                cursor: (manual && pick === null) ? 'pointer' : 'default',
                fontSize: 13, fontWeight: 700,
              }}
            >{arg}</button>
          );
        })}
      </div>
    </div>
  );
};

// ----- Furtividade: parar uma barra na zona segura -----
const MGStealth = ({ diff, onResolve, manual }) => {
  const totalMs = Math.round(5000 * diff.timeMult);
  // Zona segura aleatória entre 20% e 70% — largura escala inversamente com dificuldade
  const safeWidth = 12 + Math.round(18 * (1 - diff.aiSuccess + 0.4)); // %
  const [safeStart] = useState(() => 15 + Math.random() * (75 - safeWidth));
  const [pos, setPos] = useState(0);
  const dirRef = useRef(1);
  const [stopped, setStopped] = useState(false);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);

  useEffect(() => {
    if (stopped) return;
    let raf;
    const speed = 0.9 + (1 - diff.timeMult) * 0.6; // dificuldade alta = mais rápida
    const tick = () => {
      setPos(p => {
        let next = p + dirRef.current * speed;
        if (next >= 100) { next = 100; dirRef.current = -1; }
        if (next <= 0) { next = 0; dirRef.current = 1; }
        return next;
      });
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [stopped, diff]);

  useEffect(() => {
    if (!manual) return;
    const id = setInterval(() => {
      if (Date.now() - startRef.current >= totalMs && !resolvedRef.current) {
        clearInterval(id);
        resolvedRef.current = true;
        onResolve(false, 'Tempo esgotado · detectado');
      }
    }, 200);
    return () => clearInterval(id);
  }, [manual, totalMs]);

  useEffect(() => {
    if (manual) return;
    const t = setTimeout(() => doStop(Math.random() < diff.aiSuccess), 1200 + Math.random() * 1500);
    return () => clearTimeout(t);
  }, [manual]);

  const doStop = (forceWin) => {
    if (stopped) return;
    setStopped(true);
    let finalPos = pos;
    if (forceWin === true) finalPos = safeStart + safeWidth / 2;
    if (forceWin === false) finalPos = (safeStart + 50) % 100;
    setPos(finalPos);
    const ok = finalPos >= safeStart && finalPos <= safeStart + safeWidth;
    setTimeout(() => {
      if (resolvedRef.current) return;
      resolvedRef.current = true;
      onResolve(ok, ok ? 'Passou despercebido' : 'Foi notado nas sombras');
    }, 700);
  };

  return (
    <div style={{ textAlign: 'center', padding: 8 }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 14 }}>
        // PARE NA ZONA VERDE {manual ? '· TOQUE PRA PARAR' : '· IA'}
      </div>
      <div style={{
        position: 'relative', height: 28, background: C.bg2,
        border: `1px solid ${C.border}`, marginBottom: 18, overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', top: 0, bottom: 0,
          left: `${safeStart}%`, width: `${safeWidth}%`,
          background: '#00FF8533', border: `1px dashed #00FF85`,
        }} />
        <div style={{
          position: 'absolute', top: 0, bottom: 0, width: 4,
          left: `calc(${pos}% - 2px)`,
          background: diff.color, boxShadow: `0 0 12px ${diff.color}`,
        }} />
      </div>
      {manual && !stopped && (
        <button onClick={() => doStop()} className="clip-corner-sm" style={{
          background: diff.color, border: 'none', color: '#000',
          padding: '12px 32px', cursor: 'pointer', fontWeight: 900,
          fontSize: 14, letterSpacing: '0.2em',
        }}>PARAR</button>
      )}
    </div>
  );
};

// ----- Sobrevivência: pegue o recurso certo entre vários -----
const MGSurvival = ({ diff, onResolve, manual }) => {
  const ITEMS = [
    { id: 'water',   label: 'Água Pura',     icon: '◉', safe: true  },
    { id: 'gas',     label: 'Gasolina',      icon: '◈', safe: false },
    { id: 'ration',  label: 'Ração Sintética', icon: '▦', safe: true  },
    { id: 'acid',    label: 'Ácido Verde',   icon: '⌬', safe: false },
    { id: 'med',     label: 'Estim. Trauma', icon: '✚', safe: true  },
    { id: 'poison',  label: 'Veneno Toxico', icon: '✖', safe: false },
  ];
  const [pool] = useState(() => [...ITEMS].sort(() => Math.random() - 0.5).slice(0, 4));
  const [pick, setPick] = useState(null);
  const totalMs = Math.round(4500 * diff.timeMult);
  const [timeLeft, setTimeLeft] = useState(totalMs);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);

  useEffect(() => {
    if (!manual) return;
    const id = setInterval(() => {
      const r = Math.max(0, totalMs - (Date.now() - startRef.current));
      setTimeLeft(r);
      if (r <= 0 && !resolvedRef.current && pick === null) {
        clearInterval(id);
        resolvedRef.current = true;
        onResolve(false, 'Indecisão · nada útil pego');
      }
    }, 100);
    return () => clearInterval(id);
  }, [manual]);

  useEffect(() => {
    if (manual) return;
    const t = setTimeout(() => {
      const safe = pool.filter(p => p.safe);
      const unsafe = pool.filter(p => !p.safe);
      const chosen = (Math.random() < diff.aiSuccess && safe.length)
        ? safe[Math.floor(Math.random() * safe.length)]
        : (unsafe.length ? unsafe[Math.floor(Math.random() * unsafe.length)] : pool[0]);
      pickItem(pool.indexOf(chosen));
    }, 900 + Math.random() * 1200);
    return () => clearTimeout(t);
  }, [manual]);

  const pickItem = (i) => {
    if (pick !== null) return;
    setPick(i);
    setTimeout(() => {
      if (resolvedRef.current) return;
      resolvedRef.current = true;
      const it = pool[i];
      onResolve(!!it.safe, it.safe ? `Pegou ${it.label}` : `Pegou ${it.label} · catástrofe`);
    }, 700);
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 12 }}>
        // PESQUE O RECURSO ÚTIL {manual ? `· ${(timeLeft/1000).toFixed(1)}s` : '· IA'}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
        {pool.map((it, i) => {
          const isPick = pick === i;
          const showResult = pick !== null;
          const isSafe = showResult && it.safe;
          const bg = showResult ? (isPick ? (it.safe ? '#00FF8533' : '#FF003C33') : (isSafe ? '#00FF8511' : C.bg2)) : (isPick ? `${diff.color}33` : C.bg2);
          const bc = showResult ? (isPick ? (it.safe ? '#00FF85' : '#FF003C') : (isSafe ? '#00FF8555' : C.border)) : (isPick ? diff.color : C.border);
          return (
            <button
              key={it.id}
              onClick={() => manual && pickItem(i)}
              disabled={!manual || pick !== null}
              className="clip-corner-sm"
              style={{
                background: bg, border: `1.5px solid ${bc}`,
                color: C.text, padding: '14px 8px',
                cursor: (manual && pick === null) ? 'pointer' : 'default',
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6,
              }}
            >
              <div style={{ fontSize: 26, color: diff.color }}>{it.icon}</div>
              <div style={{ fontSize: 12, fontWeight: 700 }}>{it.label}</div>
            </button>
          );
        })}
      </div>
    </div>
  );
};

// ----- Fé: cara ou coroa -----
const MGCoinflip = ({ diff, onResolve, manual }) => {
  const [call, setCall] = useState(null); // 'cara' | 'coroa'
  const [coin, setCoin] = useState(null);
  const [flipping, setFlipping] = useState(false);
  const totalMs = Math.round(4000 * diff.timeMult);
  const [timeLeft, setTimeLeft] = useState(totalMs);
  const startRef = useRef(Date.now());
  const resolvedRef = useRef(false);

  useEffect(() => {
    if (!manual) return;
    const id = setInterval(() => {
      const r = Math.max(0, totalMs - (Date.now() - startRef.current));
      setTimeLeft(r);
      if (r <= 0 && !resolvedRef.current && call === null) {
        clearInterval(id);
        resolvedRef.current = true;
        onResolve(false, 'Hesitou · a moeda caiu no chão');
      }
    }, 100);
    return () => clearInterval(id);
  }, [manual]);

  useEffect(() => {
    if (manual) return;
    const t = setTimeout(() => {
      const guess = Math.random() < 0.5 ? 'cara' : 'coroa';
      doCall(guess);
    }, 800 + Math.random() * 900);
    return () => clearTimeout(t);
  }, [manual]);

  const doCall = (choice) => {
    if (call !== null) return;
    setCall(choice);
    setFlipping(true);
    setTimeout(() => {
      // Resultado: 50% puro, com leve viés por aiSuccess
      const win = Math.random() < (0.5 + (diff.aiSuccess - 0.5) * 0.3);
      const landed = win ? choice : (choice === 'cara' ? 'coroa' : 'cara');
      setCoin(landed);
      setFlipping(false);
      setTimeout(() => {
        if (resolvedRef.current) return;
        resolvedRef.current = true;
        onResolve(win, win ? `Disse ${choice} · caiu ${landed}` : `Disse ${choice} · caiu ${landed}`);
      }, 800);
    }, 1100);
  };

  return (
    <div style={{ textAlign: 'center', padding: 8 }}>
      <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 14 }}>
        // CHAME NO AR {manual ? `· ${(timeLeft/1000).toFixed(1)}s` : '· IA'}
      </div>
      <div style={{
        width: 110, height: 110, borderRadius: '50%', margin: '0 auto 18px',
        background: C.yellow, border: `4px solid ${C.bg2}`,
        boxShadow: `0 0 22px ${C.yellow}aa, inset 0 -4px 12px rgba(0,0,0,0.3)`,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 48, fontWeight: 900, color: '#000',
        animation: flipping ? 'd2-spin 0.25s linear infinite' : 'none',
      }}>
        {coin === 'cara' ? '☉' : coin === 'coroa' ? '★' : '?'}
      </div>
      {call === null && manual && (
        <div style={{ display: 'flex', gap: 8, justifyContent: 'center' }}>
          <button onClick={() => doCall('cara')} className="clip-corner-sm" style={{
            background: C.yellow, border: 'none', color: '#000',
            padding: '12px 22px', cursor: 'pointer', fontWeight: 900,
            fontSize: 13, letterSpacing: '0.2em',
          }}>CARA ☉</button>
          <button onClick={() => doCall('coroa')} className="clip-corner-sm" style={{
            background: C.bg2, border: `2px solid ${C.yellow}`, color: C.yellow,
            padding: '12px 22px', cursor: 'pointer', fontWeight: 900,
            fontSize: 13, letterSpacing: '0.2em',
          }}>COROA ★</button>
        </div>
      )}
      {call !== null && (
        <div className="mono" style={{
          fontSize: 12, color: C.text, letterSpacing: '0.2em', marginTop: 4,
        }}>VOCÊ DISSE: <span style={{ color: C.yellow, fontWeight: 900 }}>{call.toUpperCase()}</span></div>
      )}
    </div>
  );
};

// ----- Tela: catálogo de desafios (grupo OU particular) -----
const MasterChallenges = ({ onBack, onNav, shared, setShared, addLog, showToast, target }) => {
  const [chalDiff, setChalDiff] = useState('normal');

  const isParticular = !!(target && target.name);
  const accentColor = isParticular ? C.yellow : C.green;
  const screenTitle = isParticular ? `Desafio para ${target.name}` : 'Desafios de Grupo';

  // Lista de jogadores reais nesta mesa (criados via PlayerCreate, sync via shared)
  const realPlayerNames = (shared.tablePlayers || []).map(p => p.name);

  const launchChallenge = (typeId) => {
    const meta = CHALLENGE_CATALOG.find(c => c.id === typeId);
    // Decide o modo: se há jogador real disponível e o alvo é ele (ou é grupo), usa modo Player.
    // Caso contrário (alvo NPC ou nenhum jogador real), IA resolve.
    const targetName = isParticular ? target.name : null;
    const hasReal = realPlayerNames.length > 0;
    let mode = 'ai';
    if (hasReal) {
      if (!targetName) mode = 'player'; // grupo → jogador real resolve
      else if (realPlayerNames.includes(targetName)) mode = 'player';
    }
    addLog({
      kind: isParticular ? 'player-challenge' : 'group-challenge',
      text: `Mestre lançou desafio ${isParticular ? 'particular' : 'para o grupo'}: ${meta.name} (${getChalDiff(chalDiff).label})${isParticular ? ` → ${target.name}` : ''}`,
      color: accentColor,
      targetPlayer: isParticular ? target.name : undefined,
    });
    // Grupo: agrega o resultado de TODOS os jogadores reais. Particular: só o alvo.
    const expectedPlayers = isParticular
      ? (targetName ? [targetName] : [])
      : (realPlayerNames || []);
    setShared(s => ({
      ...s,
      pendingMinigame: {
        launchId: `${Date.now()}-${Math.floor(Math.random()*999)}`,
        type: typeId,
        difficulty: chalDiff,
        targetName,
        mode,
        expectedPlayers,
        results: {},  // { [playerName]: { success, detail } }
        result: null, // agregado final
      },
    }));
  };

  const startHack = () => {
    setShared(s => ({ ...s, pendingHack: { time: Date.now(), result: null, target: isParticular ? target.name : null } }));
    addLog({
      kind: isParticular ? 'player-challenge' : 'group-challenge',
      text: `Mestre iniciou DESAFIO ${isParticular ? `PARTICULAR (${target.name})` : 'DE GRUPO'}: Hacking (${getChalDiff(chalDiff).label})`,
      color: accentColor,
      targetPlayer: isParticular ? target.name : undefined,
    });
    showToast(`DESAFIO ${isParticular ? 'PARTICULAR' : 'DE GRUPO'} ENVIADO`, accentColor);
    onNav('master-hack');
  };

  return (
    <div style={{ minHeight: '100vh', background: C.bg, color: C.text, paddingBottom: 24 }}>
      <Header title={screenTitle} onBack={onBack} />

      <div style={{ padding: 16 }}>
        <div className="mono" style={{ color: C.textDim, fontSize: 10, letterSpacing: '0.2em', marginBottom: 8 }}>
          // DIFICULDADE
        </div>
        <div style={{ display: 'flex', gap: 6, marginBottom: 16 }}>
          {CHALLENGE_DIFFS.map(d => {
            const active = chalDiff === d.id;
            return (
              <button
                key={d.id}
                onClick={() => setChalDiff(d.id)}
                className="clip-corner-sm"
                style={{
                  flex: 1,
                  background: active ? `${d.color}22` : C.bg2,
                  border: `1.5px solid ${active ? d.color : C.border}`,
                  color: active ? d.color : C.textDim,
                  padding: '10px',
                  cursor: 'pointer',
                  fontSize: 12,
                  fontWeight: 700,
                  letterSpacing: '0.1em',
                }}
              >{d.label.toUpperCase()}</button>
            );
          })}
        </div>

        <div className="mono" style={{ color: C.textDim, fontSize: 10, letterSpacing: '0.2em', marginBottom: 8 }}>
          // CATÁLOGO · {CHALLENGE_CATALOG.length} DESAFIOS{isParticular ? ` · DESTINO: ${target.name.toUpperCase()}` : ''}
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {CHALLENGE_CATALOG.map(c => (
            <button
              key={c.id}
              onClick={() => launchChallenge(c.id)}
              className="clip-corner-sm"
              style={{
                width: '100%',
                background: C.bg2,
                border: `1.5px solid ${c.color}`,
                color: C.text,
                padding: '12px 14px',
                cursor: 'pointer',
                textAlign: 'left',
                display: 'flex',
                gap: 14,
                alignItems: 'center',
              }}
            >
              <div style={{ fontSize: 28, color: c.color, flexShrink: 0 }}>{c.icon}</div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div className="mono" style={{ fontSize: 9, color: c.color, letterSpacing: '0.2em' }}>DESAFIO</div>
                <div style={{ fontSize: 15, fontWeight: 700 }}>{c.name}</div>
                <div style={{ fontSize: 11, color: C.textDim }}>{c.desc}</div>
              </div>
              <div style={{ color: c.color, fontSize: 16 }}>▶</div>
            </button>
          ))}

        </div>

        <div className="mono" style={{ marginTop: 16, color: C.textDim, fontSize: 10, letterSpacing: '0.15em', textAlign: 'center', fontStyle: 'italic' }}>
          // IA RESPONDE {isParticular ? 'PELO JOGADOR' : 'PELO GRUPO'} ENQUANTO ESTAMOS NO MVP
        </div>
      </div>

    </div>
  );
};

// ----- Runner modal (fullscreen, sem como escapar) -----
// Lê shared.pendingMinigame. Renderiza:
// - Modo IA (mestre joga, jogador vê "aguardando" se aplicável)
// - Modo Player (jogador joga manualmente, mestre vê "aguardando")
// - Resultado (ambos veem por 1.6s, depois mestre limpa o pending)
// ============== COMBAT OVERLAY (sincronizado entre abas) ==============
// Lê shared.combat.event e renderiza o modal correspondente.
// Master tab dirige (emite eventos via setShared); player tab só observa.
const CombatTimeline = ({ queue = [], turnIndex = 0, summoned = [] }) => (
  <div style={{
    display: 'flex', overflowX: 'auto', gap: 6,
    padding: '10px 12px', borderBottom: `1px solid ${C.border}`,
    background: 'rgba(0,0,0,0.5)',
  }}>
    {queue.map((q, i) => {
      const isCurrent = i === turnIndex;
      const isPast = i < turnIndex;
      let color = C.cyan;
      if (q.kind === 'enemy') color = C.magenta;
      else if (q.kind === 'ally') color = '#00FF85';
      // Verifica se NPC está vivo
      let alive = true;
      if (q.instanceId) {
        const inst = summoned.find(x => x.instanceId === q.instanceId);
        alive = inst && (inst.hp || 0) > 0;
      }
      return (
        <div key={i} className="clip-corner-sm" style={{
          background: isCurrent ? color : C.bg2,
          border: `1px solid ${isCurrent ? color : C.border}`,
          color: isCurrent ? '#000' : (isPast ? C.textDim : C.text),
          padding: '4px 8px',
          fontSize: 10, fontWeight: 700, letterSpacing: '0.08em',
          opacity: alive ? (isPast ? 0.45 : 1) : 0.25,
          textDecoration: alive ? 'none' : 'line-through',
          whiteSpace: 'nowrap', flexShrink: 0,
          animation: isCurrent ? 'fade-in 0.25s' : 'none',
        }}>
          {q.kind === 'player' ? '◆' : q.kind === 'ally' ? '✦' : '✺'} {q.name.slice(0, 14)}
        </div>
      );
    })}
  </div>
);

const D2Circle = ({ result, delayMs = 0, title }) => {
  // result: 'hit' | 'miss' | 'boss' | undefined
  const [phase, setPhase] = useState('spinning'); // 'spinning' | 'settled'
  useEffect(() => {
    if (!result) { setPhase('spinning'); return; }
    setPhase('spinning');
    const t = setTimeout(() => setPhase('settled'), 1300 + delayMs);
    return () => clearTimeout(t);
  }, [result, delayMs]);

  const finalColor = result === 'boss' ? '#FCEE0A' : result === 'hit' ? '#00FF85' : result === 'miss' ? '#FF003C' : C.bg3;
  const isSpinning = phase === 'spinning' && !!result;

  if (isSpinning) {
    // Durante o giro: gradiente cônico animado entre as cores possíveis
    return (
      <div title={title} style={{
        aspectRatio: '1/1', borderRadius: '50%',
        background: 'conic-gradient(#00FF85, #FF003C, #FCEE0A, #00FF85)',
        border: `2px solid rgba(255,255,255,0.4)`,
        animation: 'd2-spin 0.35s linear infinite',
        boxShadow: '0 0 12px rgba(255,255,255,0.3)',
      }} />
    );
  }
  return (
    <div title={title} style={{
      aspectRatio: '1/1', borderRadius: '50%',
      background: finalColor,
      border: `2px solid ${finalColor === C.bg3 ? C.border : finalColor}`,
      boxShadow: finalColor !== C.bg3 ? `0 0 22px ${finalColor}aa, 0 0 44px ${finalColor}55` : 'none',
      animation: result ? 'd2-circle-pop 0.55s cubic-bezier(0.34, 1.56, 0.64, 1)' : 'none',
      transition: 'all 0.5s',
    }} />
  );
};

const D2BatchPanel = ({ event, summoned }) => {
  // event: { side: 'enemy'|'ally', rolls: { [instanceId]: 'hit'|'miss'|'boss' }, count, total }
  const sideLabel = event.side === 'enemy' ? 'OS INIMIGOS ESTÃO REAGINDO...' : 'OS ALIADOS ESTÃO REAGINDO...';
  const sideColor = event.side === 'enemy' ? C.magenta : '#00FF85';
  const slots = Array.from({ length: 10 }, (_, i) => summoned.filter(inst => {
    const t = getDifficulty(inst.diffId).type;
    return event.side === 'enemy' ? t !== 'ally' : t === 'ally';
  })[i] || null);
  return (
    <div style={{ textAlign: 'center', padding: '20px 12px' }}>
      <div className="mono" style={{ fontSize: 12, color: sideColor, letterSpacing: '0.3em', fontWeight: 700, marginBottom: 18 }}>
        // {sideLabel}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 10, maxWidth: 300, margin: '0 auto 18px' }}>
        {slots.map((inst, i) => {
          if (!inst) {
            return <div key={i} style={{
              aspectRatio: '1/1', borderRadius: '50%',
              border: '1px solid rgba(255,255,255,0.18)',
            }} />;
          }
          // NPC morto: círculo escuro com X, desativado (não rola d2).
          const isDead = (inst.hp || 0) <= 0 && inst.maxHp !== undefined;
          if (isDead) {
            return (
              <div key={inst.instanceId} title={`${inst.name} · K.O.`} style={{
                aspectRatio: '1/1', borderRadius: '50%',
                background: 'rgba(0,0,0,0.55)',
                border: `1px solid ${C.border}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                opacity: 0.55,
              }}>
                <span style={{ color: '#888', fontSize: 22, fontWeight: 900, lineHeight: 1 }}>✕</span>
              </div>
            );
          }
          const r = event.rolls?.[inst.instanceId];
          return (
            <D2Circle
              key={inst.instanceId}
              result={r}
              delayMs={i * 120}
              title={inst.name}
            />
          );
        })}
      </div>
      {event.showCount && (
        <div style={{ animation: 'fade-in 0.3s' }}>
          <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginBottom: 6 }}>
            // TURNO DEFINIDO
          </div>
          <div style={{ fontSize: 28, fontWeight: 900, color: sideColor, fontFamily: "'Orbitron', sans-serif" }}>
            {event.count}/{event.total}
          </div>
          <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.2em', marginTop: 2 }}>
            ATACANTES
          </div>
        </div>
      )}
      {!event.showCount && (
        <div className="mono" style={{ fontSize: 9, color: C.textDim, letterSpacing: '0.25em', opacity: 0.7 }}>
          ACERTO D2 50% · <span style={{ color: '#00FF85' }}>VERDE</span> ACERTOU · <span style={{ color: '#FF003C' }}>VERMELHO</span> ERROU · <span style={{ color: '#FCEE0A' }}>AMARELO</span> CHEFE
        </div>
      )}
    </div>
  );
};

const AttackBattlePanel = ({ event }) => (
  <div style={{ padding: '20px 16px', textAlign: 'center' }}>
    {event.targetIsPlayer ? (
      <>
        <div className="mono" style={{ fontSize: 10, color: C.magenta, letterSpacing: '0.25em', marginBottom: 4 }}>
          // {(event.attackerName || '').toUpperCase()} ESTÁ ATACANDO
        </div>
        <div style={{
          fontSize: 24, fontWeight: 900, color: C.yellow,
          fontFamily: "'Orbitron', sans-serif",
          letterSpacing: '0.04em',
          textShadow: `0 0 14px ${C.yellow}88, 0 0 28px ${C.yellow}44`,
          animation: 'blood-pulse 1.5s infinite',
        }}>{(event.defenderName || '').toUpperCase()}</div>
      </>
    ) : (
      <div className="mono" style={{ fontSize: 10, color: C.magenta, letterSpacing: '0.25em' }}>
        // {(event.attackerName || '').toUpperCase()} ESTÁ ATACANDO {(event.defenderName || '').toUpperCase()}
      </div>
    )}
    {event.defenderInfo && (
      <div className="mono" style={{ fontSize: 10, color: C.textDim, letterSpacing: '0.15em', marginTop: 4 }}>
        {event.defenderInfo}
      </div>
    )}
    <div style={{ fontSize: 16, fontWeight: 700, color: C.text, marginTop: 12, marginBottom: 22, letterSpacing: '0.02em' }}>
      Batalha de dados
    </div>
    <div style={{ display: 'flex', justifyContent: 'space-around', alignItems: 'center', marginBottom: 24 }}>
      <div style={{ textAlign: 'center' }}>
        <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.2em', marginBottom: 8 }}>
          {(event.attackerName || '').toUpperCase().slice(0,16)}
        </div>
        <div className="mono" style={{
          fontSize: 64, fontWeight: 900, lineHeight: 1,
          color: event.phase === 'rolling' ? C.cyan : (event.hit ? C.green : C.magenta),
          textShadow: event.phase === 'reveal'
            ? (event.hit ? `0 0 28px ${C.green}, 0 0 60px ${C.green}66` : `0 0 28px ${C.magenta}, 0 0 60px ${C.magenta}66`)
            : `0 0 14px ${C.cyan}66`,
          animation: event.phase === 'rolling'
            ? 'dice-shake 0.42s infinite, dice-rolling-spin 1.4s linear infinite'
            : 'reveal-pop 0.55s cubic-bezier(0.34, 1.56, 0.64, 1)',
          transition: 'color 0.3s, text-shadow 0.3s',
        }}>{event.phase === 'rolling' ? '?' : event.aRoll}</div>
      </div>
      <div style={{ fontSize: 36, color: C.textDim, fontWeight: 900, fontFamily: "'Orbitron', sans-serif" }}>×</div>
      <div style={{ textAlign: 'center' }}>
        <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.2em', marginBottom: 8 }}>
          {(event.defenderName || '').toUpperCase().slice(0,16)}
        </div>
        <div className="mono" style={{
          fontSize: 64, fontWeight: 900, lineHeight: 1,
          color: event.phase === 'rolling' ? C.cyan : (event.hit ? C.magenta : C.green),
          textShadow: event.phase === 'reveal'
            ? (event.hit ? `0 0 28px ${C.magenta}, 0 0 60px ${C.magenta}66` : `0 0 28px ${C.green}, 0 0 60px ${C.green}66`)
            : `0 0 14px ${C.cyan}66`,
          animation: event.phase === 'rolling'
            ? 'dice-shake 0.42s infinite, dice-rolling-spin 1.4s linear infinite'
            : 'reveal-pop 0.55s cubic-bezier(0.34, 1.56, 0.64, 1) 0.15s backwards',
          transition: 'color 0.3s, text-shadow 0.3s',
        }}>{event.phase === 'rolling' ? '?' : event.dRoll}</div>
      </div>
    </div>
    {event.phase === 'reveal' && (
      <div style={{
        fontSize: 22, color: event.hit ? C.green : C.cyan,
        letterSpacing: '0.25em', fontWeight: 900,
        fontFamily: "'Orbitron', sans-serif",
        animation: 'reveal-pop 0.5s cubic-bezier(0.34, 1.56, 0.64, 1), verdict-glow 1.5s ease-out forwards',
        marginTop: 8,
      }}>
        {event.hit ? 'ACERTADO!' : 'DESVIOU!'}
      </div>
    )}
  </div>
);

const DamagePanel = ({ event }) => (
  <div style={{
    padding: '36px 16px', textAlign: 'center',
    animation: 'screen-shake 0.55s ease-out',
  }}>
    <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.3em', marginBottom: 22 }}>
      // {(event.defenderName || '').toUpperCase()}
    </div>
    <div style={{
      fontSize: 96, fontWeight: 900, color: '#FFFFFF',
      fontFamily: "'Orbitron', sans-serif",
      letterSpacing: '0.01em',
      lineHeight: 1,
      WebkitTextStroke: `2.5px ${C.magenta}`,
      textShadow: `0 0 24px ${C.magenta}, 0 0 50px ${C.magenta}aa, 0 0 90px ${C.magenta}66`,
      animation: 'damage-impact 0.75s cubic-bezier(0.34, 1.56, 0.64, 1)',
    }}>−{event.dmg} HP</div>
    <div className="mono" style={{
      fontSize: event.isKO ? 18 : 13,
      color: event.isKO ? C.magenta : C.textDim,
      letterSpacing: '0.3em',
      fontWeight: event.isKO ? 900 : 600,
      marginTop: 20,
      fontStyle: event.isKO ? 'normal' : 'italic',
      fontFamily: event.isKO ? "'Orbitron', sans-serif" : 'inherit',
      textShadow: event.isKO ? `0 0 16px ${C.magenta}` : 'none',
      animation: event.isKO ? 'reveal-pop 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) 0.3s backwards' : 'fade-in 0.4s 0.3s backwards',
    }}>
      {event.isKO ? '✕ MORREU ✕' : 'Essa doeu'}
    </div>
  </div>
);

const MissPanel = ({ event }) => {
  const panic = !!event.panic;
  const playerDodged = !panic && event.dodgerKind === 'player';
  const enemyDodged = !panic && event.dodgerKind === 'enemy';
  // Cores e ícones distintos pra deixar claro QUEM desviou (ou se o inimigo entrou em pânico).
  const accent = panic ? '#FF6E2C' : playerDodged ? '#00FF85' : enemyDodged ? '#FF003C' : C.cyan;
  const icon = panic ? '✕' : playerDodged ? '✦' : enemyDodged ? '⌬' : '↯';
  const badge = panic
    ? 'PÂNICO'
    : playerDodged
      ? 'JOGADOR DESVIOU'
      : enemyDodged
        ? 'INIMIGO DESVIOU'
        : null;
  const verb = panic ? 'PÂNICO!' : playerDodged ? 'DESVIADO!' : 'DESVIOU';
  const subtitle = panic
    ? `${event.attackerName || 'Inimigo'} entrou em pânico e não atacou ninguém`
    : playerDodged
      ? `${event.defenderName || ''} desviou do ataque de ${event.attackerName || ''}!`
      : enemyDodged
        ? `${event.defenderName || ''} esquivou de ${event.attackerName || ''}`
        : `${event.defenderName || ''} esquivou de ${event.attackerName || ''}`;
  return (
    <div style={{ padding: '36px 16px', textAlign: 'center' }}>
      {badge && (
        <div className="mono" style={{
          display: 'inline-block',
          fontSize: 11, color: '#000', background: accent,
          padding: '4px 12px',
          letterSpacing: '0.35em', fontWeight: 900,
          marginBottom: 14,
          animation: 'reveal-pop 0.4s cubic-bezier(0.34, 1.56, 0.64, 1)',
          boxShadow: `0 0 18px ${accent}aa`,
        }}>
          // {badge}
        </div>
      )}
      <div style={{
        fontSize: 96, color: accent, marginBottom: 16,
        animation: 'reveal-pop 0.65s cubic-bezier(0.34, 1.56, 0.64, 1)',
        textShadow: `0 0 24px ${accent}aa, 0 0 50px ${accent}55`,
        lineHeight: 1,
      }}>{icon}</div>
      <div style={{
        fontSize: 22, color: accent, letterSpacing: '0.35em', fontWeight: 900,
        fontFamily: "'Orbitron', sans-serif",
        textShadow: `0 0 16px ${accent}`,
        animation: 'reveal-pop 0.55s cubic-bezier(0.34, 1.56, 0.64, 1) 0.15s backwards',
      }}>
        {verb}
      </div>
      <div style={{
        fontSize: 13, color: C.textDim, marginTop: 14, fontStyle: 'italic',
        animation: 'fade-in 0.5s 0.4s backwards',
      }}>
        {subtitle}
      </div>
    </div>
  );
};

const TurnBannerPanel = ({ event }) => (
  <div style={{ padding: '40px 16px', textAlign: 'center', animation: 'fade-in 0.25s' }}>
    <div className="mono" style={{ fontSize: 10, color: C.textDim, letterSpacing: '0.3em', marginBottom: 10 }}>
      // {event.subtitle || 'PRÓXIMA ETAPA'}
    </div>
    <div style={{
      fontSize: 30, fontWeight: 900, color: C.yellow,
      fontFamily: "'Orbitron', sans-serif", letterSpacing: '0.05em',
      textShadow: `0 0 14px ${C.yellow}88`,
    }}>{event.text}</div>
  </div>
);

