const ChallengeRunner = ({ pending, role, isPlayer, playerName, setShared, addLog, showToast }) => {
  const isMaster = role === 'master';
  const resolvingRef = useRef(false);

  // Reseta a trava de "já resolvido" quando muda o desafio (novo launchId)
  const launchId = pending && pending.launchId;
  useEffect(() => { resolvingRef.current = false; }, [launchId]);

  const result = pending && pending.result;
  const type = pending && pending.type;
  const difficulty = pending && pending.difficulty;
  const targetName = pending && pending.targetName;
  const mode = pending && pending.mode;
  const meta = type ? CHALLENGE_CATALOG.find(c => c.id === type) : null;
  const diff = difficulty ? getChalDiff(difficulty) : null;
  const targetLabel = targetName || 'Grupo';

  // Quando result aparece, mestre loga + limpa; jogador só toca
  useEffect(() => {
    if (!result || !pending || !meta || !diff) return;
    if (isMaster) {
      addLog({
        kind: result.success ? 'challenge-success' : 'challenge-fail',
        text: `Desafio ${result.success ? 'concluído' : 'falhou'}: ${meta.name} (${diff.label}) → ${targetLabel}`,
        color: result.success ? C.green : C.magenta,
      });
      showToast(result.success ? `${meta.name.toUpperCase()}: SUCESSO` : `${meta.name.toUpperCase()}: FALHA`, result.success ? C.green : C.magenta);
      const t = setTimeout(() => {
        setShared(s => ({ ...s, pendingMinigame: null }));
      }, 1700);
      return () => clearTimeout(t);
    } else {
      showToast(result.success ? 'SUCESSO' : 'FALHA', result.success ? C.green : C.magenta);
    }
  }, [result && result.success, isMaster, launchId]);

  if (!pending || !meta || !diff) return null;

  // Quem deve renderizar/operar o minigame?
  const masterPlaysAI = isMaster && mode === 'ai';
  const playerPlaysManual = isPlayer && mode === 'player' && playerName === targetName;
  const playerPlaysGroup = isPlayer && mode === 'player' && !targetName;
  const playerPlays = playerPlaysManual || playerPlaysGroup;
  const masterWaiting = isMaster && mode === 'player' && !result;

  const handleResolve = (ok, detail) => {
    if (resolvingRef.current) return;
    resolvingRef.current = true;
    setShared(s => {
      if (!s.pendingMinigame) return s;
      const pg = s.pendingMinigame;
      const who = playerName || '_anon';
      const prevResults = pg.results || {};
      // Já registrou? mantém.
      if (prevResults[who]) return s;
      const nextResults = { ...prevResults, [who]: { success: !!ok, detail: detail || '' } };
      const expected = pg.expectedPlayers || (pg.targetName ? [pg.targetName] : []);
      const allDone = expected.length > 0 && expected.every(n => nextResults[n]);
      let aggregate = pg.result;
      if (allDone && !aggregate) {
        const list = expected.map(n => nextResults[n]).filter(Boolean);
        const wins = list.filter(r => r.success).length;
        const losses = list.length - wins;
        if (wins === losses) {
          aggregate = {
            success: true,
            weak: true,
            detail: 'Passou por pouco · os NPCs estão suspeitos',
            tally: { wins, losses, total: list.length },
          };
        } else {
          aggregate = {
            success: wins > losses,
            detail: `${wins} sucesso · ${losses} falha`,
            tally: { wins, losses, total: list.length },
          };
        }
      }
      return {
        ...s,
        pendingMinigame: { ...pg, results: nextResults, result: aggregate || null },
      };
    });
  };

  return (
    <div style={{
      position: 'fixed', inset: 0,
      background: 'rgba(0,0,0,0.92)',
      zIndex: 90,
      display: 'flex', flexDirection: 'column',
      animation: 'fade-in 0.2s',
    }}>
      {/* Header sem botão de fechar */}
      <div style={{ padding: '20px 16px 12px', borderBottom: `1px solid ${C.border}`, textAlign: 'center' }}>
        <div className="mono" style={{ fontSize: 10, color: diff.color, letterSpacing: '0.3em' }}>
          // DESAFIO {String(targetLabel).toUpperCase()} · {diff.label.toUpperCase()}
        </div>
        <div style={{ fontSize: 22, fontWeight: 700, color: C.text, marginTop: 4, letterSpacing: '0.02em' }}>
          {meta.icon} {meta.name}
        </div>
        <div className="mono" style={{ fontSize: 10, color: C.textDim, letterSpacing: '0.15em', marginTop: 2 }}>
          {meta.desc}
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
        {/* Caso: resultado revelado */}
        {result && (
          <div style={{ textAlign: 'center', animation: 'fade-in 0.3s' }}>
            <div style={{
              fontSize: 88, fontWeight: 900,
              color: result.success ? (result.weak ? C.yellow : C.green) : '#FFFFFF',
              textShadow: result.success
                ? (result.weak ? `0 0 24px ${C.yellow}` : `0 0 24px ${C.green}`)
                : `0 0 18px #E60026, 0 0 28px #E60026`,
              WebkitTextStroke: result.success ? 'none' : '2px #E60026',
              fontFamily: "'Orbitron', sans-serif",
              letterSpacing: '0.05em',
              animation: result.success ? 'none' : 'blood-pulse 1.5s infinite',
            }}>{result.success ? (result.weak ? 'POR POUCO' : 'OK') : 'FALHA'}</div>
            {result.tally && (
              <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em', marginTop: 6 }}>
                {result.tally.wins} SUCESSO · {result.tally.losses} FALHA · {result.tally.total} JOGADOR(ES)
              </div>
            )}
            <div className="mono" style={{ fontSize: 12, color: C.textDim, letterSpacing: '0.2em', marginTop: 10 }}>
              {result.detail}
            </div>
          </div>
        )}

        {/* Caso: jogando (master IA ou player manual) */}
        {!result && (masterPlaysAI || playerPlays) && (
          <div style={{ width: '100%', maxWidth: 360 }}>
            {type === 'reflex'     && <MGReflex     diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'force'      && <MGForce      diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'lockpick'   && <MGLockpick   diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'perception' && <MGPerception diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'hack'       && <MGHack       diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'romance'    && <MGRomance    diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'persuasion' && <MGPersuasion diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'stealth'    && <MGStealth    diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'survival'   && <MGSurvival   diff={diff} manual={playerPlays} onResolve={handleResolve} />}
            {type === 'coinflip'   && <MGCoinflip   diff={diff} manual={playerPlays} onResolve={handleResolve} />}
          </div>
        )}

        {/* Caso: mestre aguardando jogador */}
        {!result && masterWaiting && (
          <div style={{ textAlign: 'center', padding: 20 }}>
            <div className="mono" style={{ fontSize: 11, color: diff.color, letterSpacing: '0.25em', marginBottom: 16 }}>
              // AGUARDANDO {targetLabel.toUpperCase()}
            </div>
            <div style={{ fontSize: 64, color: diff.color, animation: 'glitch-flicker 1.4s infinite' }}>{meta.icon}</div>
            <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.15em', marginTop: 16 }}>
              o jogador está resolvendo o desafio na outra aba
            </div>
          </div>
        )}

        {/* Caso: jogador na aba errada (não é o alvo nem é grupo) — apenas vê o desafio rolando */}
        {!result && !masterPlaysAI && !playerPlays && !masterWaiting && (
          <div style={{ textAlign: 'center', padding: 20 }}>
            <div className="mono" style={{ fontSize: 11, color: C.textDim, letterSpacing: '0.25em' }}>
              // DESAFIO EM ANDAMENTO PARA {targetLabel.toUpperCase()}
            </div>
          </div>
        )}
      </div>

      <div className="mono" style={{ padding: 14, textAlign: 'center', color: C.textDim, fontSize: 9, letterSpacing: '0.25em', borderTop: `1px solid ${C.border}` }}>
        // {mode === 'ai' ? 'IA RESOLVENDO' : 'JOGADOR RESOLVENDO'} · NÃO É POSSÍVEL ESCAPAR
      </div>
    </div>
  );
};

// ============== TELA: LOG (compartilhada) ==============
const LogScreen = ({ onBack, shared, role }) => (
  <div style={{ minHeight: '100vh', background: C.bg, color: C.text }}>
    <Header title={role === 'master' ? 'Log da Partida' : 'Notificações'} onBack={onBack} />
    <div style={{ padding: 16 }}>
      <div className="mono" style={{ color: C.textDim, fontSize: 10, letterSpacing: '0.2em', marginBottom: 12 }}>
        // {shared.log.length} EVENTOS · MAIS RECENTES PRIMEIRO
      </div>
      {shared.log.length === 0 ? (
        <div style={{
          padding: 40,
          textAlign: 'center',
          color: C.textDim,
          border: `1px dashed ${C.border}`,
        }} className="clip-corner-sm">
          Nenhum evento ainda. Role um dado ou mande uma ação pro jogador.
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {[...shared.log].reverse().map((ev, i) => (
            <div key={i} className="clip-corner-sm" style={{
              background: C.bg2,
              borderLeft: `3px solid ${ev.color || C.yellow}`,
              padding: '12px 14px',
              animation: 'fade-in 0.3s',
            }}>
              <div style={{ fontSize: 14, color: C.text }}>{ev.text}</div>
              <div className="mono" style={{ fontSize: 10, color: C.textDim, marginTop: 4, letterSpacing: '0.1em' }}>
                {new Date(ev.time).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  </div>
);

