// ============== APP ROOT ==============
export default function CyberApp() {
  // Perfil ativo desta aba (ID do slot) — define automaticamente o role.
  const [activeProfile, setActiveProfileState] = useState(() => getActiveProfile());
  const profileSlot = PROFILE_SLOTS.find(s => s.id === activeProfile) || null;
  // ID único da aba pro GM-lock (vive enquanto a aba existir).
  const tabIdRef = useRef(`tab-${Date.now()}-${Math.random().toString(36).slice(2,7)}`);
  const firebaseSharedUnsub = useRef(null);
  const [role, setRole] = useState(profileSlot ? profileSlot.role : null);
  const [screen, setScreen] = useState(
    profileSlot
      ? (profileSlot.role === 'master' ? 'master-mesas' : 'player-mesas')
      : 'profile-picker'
  );
  const [player, setPlayer] = useState(null);
  const [shared, setSharedState] = useState(initialSharedState);
  // Persistência em localStorage com sync cross-tab — sem isso, o player numa aba diferente
  // não enxerga a mesa criada pelo master, e o code lookup falha.
  const loadFromLS = (key, fallback) => {
    try {
      const raw = (typeof window !== 'undefined') && window.localStorage && window.localStorage.getItem(key);
      if (raw) return JSON.parse(raw);
    } catch (e) {}
    return fallback;
  };
  const [mesas, setMesas] = useState(() => loadFromLS('cyberapp:mesas', INITIAL_MESAS));
  const [mesaStates, setMesaStates] = useState(() => loadFromLS('cyberapp:mesaStates', {}));
  // Chaves do jogador são per-slot: cada perfil tem seu histórico/personagens isolado.
  const joinedKey = activeProfile ? profileKey(activeProfile, 'joinedMesaIds') : 'cyberapp:joinedMesaIds';
  const playerByMesaKey = activeProfile ? profileKey(activeProfile, 'playerByMesa') : 'cyberapp:playerByMesa';
  const [joinedMesaIds, setJoinedMesaIds] = useState(() => loadFromLS(joinedKey, []));
  // ID da mesa em que o GM está PRESENTE neste momento (null = GM fora de qualquer mesa)
  const [gmActiveMesaId, setGmActiveMesaId] = useState(() => loadFromLS('cyberapp:gmActiveMesaId', null));
  const [playerByMesa, setPlayerByMesa] = useState(() => loadFromLS(playerByMesaKey, {})); // { [mesaId]: pcObj } — persistido
  // Presença ao vivo de jogadores por mesa: { [mesaId]: [name1, name2, ...] }. Sync cross-tab.
  const [livePlayersByMesa, setLivePlayersByMesa] = useState(() => loadFromLS('cyberapp:livePlayersByMesa', {}));
  // Heartbeat com timestamps: { [mesaId]: { [name]: lastSeenMs } }. Usado pra detectar
  // ausência (tab em background, sem perder presença na mesa). Mais frio = "AUSENTE".
  const [presenceTimestamps, setPresenceTimestamps] = useState(() => loadFromLS('cyberapp:presenceTs', {}));
  // Tick local pra forçar re-render do badge de AUSENTE conforme tempo passa
  const [, setPresenceTick] = useState(0);
  useEffect(() => {
    const t = setInterval(() => setPresenceTick(x => x + 1), 5000);
    return () => clearInterval(t);
  }, []);

  // Persiste em LS toda mudança e ouve mudanças de outras abas.
  useEffect(() => { try { window.localStorage.setItem('cyberapp:mesas', JSON.stringify(mesas)); } catch (e) {} }, [mesas]);
  useEffect(() => { try { window.localStorage.setItem('cyberapp:mesaStates', JSON.stringify(mesaStates)); } catch (e) {} }, [mesaStates]);
  useEffect(() => { try { window.localStorage.setItem('cyberapp:gmActiveMesaId', JSON.stringify(gmActiveMesaId)); } catch (e) {} }, [gmActiveMesaId]);
  useEffect(() => { try { window.localStorage.setItem('cyberapp:livePlayersByMesa', JSON.stringify(livePlayersByMesa)); } catch (e) {} }, [livePlayersByMesa]);
  useEffect(() => { try { window.localStorage.setItem('cyberapp:presenceTs', JSON.stringify(presenceTimestamps)); } catch (e) {} }, [presenceTimestamps]);
  // Persistência per-slot precisa rastrear "a qual perfil pertence o estado atual em memória",
  // senão na troca de perfil o effect persist escreve dados do perfil antigo no key do novo.
  const currentJoinedKeyRef = useRef(joinedKey);
  const currentPlayerByMesaKeyRef = useRef(playerByMesaKey);
  useEffect(() => {
    try { window.localStorage.setItem(currentJoinedKeyRef.current, JSON.stringify(joinedMesaIds)); } catch (e) {}
  }, [joinedMesaIds]);
  useEffect(() => {
    try { window.localStorage.setItem(currentPlayerByMesaKeyRef.current, JSON.stringify(playerByMesa)); } catch (e) {}
  }, [playerByMesa]);
  // Quando o perfil ativo muda (switchProfile/pickProfile), atualiza os refs ANTES de
  // carregar os dados — assim os persist effects nunca escrevem em key errado.
  useEffect(() => {
    currentJoinedKeyRef.current = joinedKey;
    currentPlayerByMesaKeyRef.current = playerByMesaKey;
    setJoinedMesaIds(loadFromLS(joinedKey, []));
    setPlayerByMesa(loadFromLS(playerByMesaKey, {}));
  }, [activeProfile]);
  useEffect(() => { try { window.localStorage.setItem('cyberapp:livePlayersByMesa', JSON.stringify(livePlayersByMesa)); } catch (e) {} }, [livePlayersByMesa]);

  // ===== FIREBASE SYNC — sincroniza estado entre dispositivos diferentes =====
  useFirebaseSync('shared/mesas', mesas, setMesas, { enabled: true });
  useFirebaseSync('shared/mesaStates', mesaStates, setMesaStates, { enabled: true });
  useFirebaseSync('shared/gmActiveMesaId', gmActiveMesaId, setGmActiveMesaId, { enabled: true });
  useFirebaseSync('shared/livePlayersByMesa', livePlayersByMesa, setLivePlayersByMesa, { enabled: true });
  useFirebaseSync('shared/presenceTs', presenceTimestamps, setPresenceTimestamps, { enabled: true });
  const playerFirebasePath = activeProfile ? `players/${activeProfile}/joinedMesaIds` : null;
  const playerByMesaFirebasePath = activeProfile ? `players/${activeProfile}/playerByMesa` : null;
  useFirebaseSync(playerFirebasePath, joinedMesaIds, setJoinedMesaIds, { enabled: !!activeProfile });
  useFirebaseSync(playerByMesaFirebasePath, playerByMesa, setPlayerByMesa, { enabled: !!activeProfile });

  // Quando o GM sai de uma mesa (gmActiveMesaId vira null OU muda para outra),
  // qualquer jogador que ainda esteja nessa mesa é expulso de volta pra lista de mesas.
  const lastGmActiveRef = useRef(gmActiveMesaId);
  useEffect(() => {
    const prev = lastGmActiveRef.current;
    lastGmActiveRef.current = gmActiveMesaId;
    if (!prev) return;
    // GM acabou de SAIR da mesa "prev"
    if (gmActiveMesaId !== prev && role === 'player' && activeMesaId === prev) {
      showToast('GM SAIU DA MESA · EXPULSO', C.magenta);
      // Persiste snapshot, sai pra lista de mesas, remove de online
      setMesaStates(ms => ({ ...ms, [activeMesaId]: { ...shared, isRunning: false } }));
      if (player?.name) {
        setLivePlayersByMesa(map => {
          const cur = map[activeMesaId] || [];
          return { ...map, [activeMesaId]: cur.filter(n => n !== player.name) };
        });
      }
      setActiveMesaId(null);
      setPlayer(null);
      setScreen('player-mesas');
    }
  }, [gmActiveMesaId]);

  useEffect(() => {
    const onStorage = (e) => {
      if (!e.key) return;
      try {
        if (e.key === 'cyberapp:mesas' && e.newValue) setMesas(JSON.parse(e.newValue));
        if (e.key === 'cyberapp:mesaStates' && e.newValue) setMesaStates(JSON.parse(e.newValue));
        if (e.key === joinedKey && e.newValue) setJoinedMesaIds(JSON.parse(e.newValue));
        if (e.key === 'cyberapp:gmActiveMesaId') setGmActiveMesaId(e.newValue ? JSON.parse(e.newValue) : null);
        if (e.key === playerByMesaKey && e.newValue) setPlayerByMesa(JSON.parse(e.newValue));
        if (e.key === 'cyberapp:livePlayersByMesa' && e.newValue) setLivePlayersByMesa(JSON.parse(e.newValue));
        if (e.key === 'cyberapp:presenceTs' && e.newValue) setPresenceTimestamps(JSON.parse(e.newValue));
      } catch (err) {}
    };
    window.addEventListener('storage', onStorage);
    return () => window.removeEventListener('storage', onStorage);
  }, [joinedKey, playerByMesaKey]);
  const [activeMesaId, setActiveMesaId] = useState(null);
  const [selectedPlayer, setSelectedPlayer] = useState(null); // nome do jogador focado em telas de ação do mestre
  const [toast, setToast] = useState(null);
  const [toastColor, setToastColor] = useState(C.yellow);
  const toastTimerRef = useRef(null);

  // Ref pra sempre acessar o estado mais recente dentro dos intervals
  const sharedRef = useRef(shared);
  useEffect(() => { sharedRef.current = shared; }, [shared]);

  // PRESENÇA AO VIVO: registra/desregistra o jogador atual nesta mesa.
  // Declarado DEPOIS de activeMesaId/player pra evitar TDZ.
  useEffect(() => {
    if (role !== 'player' || !activeMesaId || !player?.name) return;
    const mesaId = activeMesaId;
    const name = player.name;
    setLivePlayersByMesa(s => {
      const cur = s[mesaId] || [];
      if (cur.includes(name)) return s;
      return { ...s, [mesaId]: [...cur, name] };
    });
    const cleanup = () => {
      setLivePlayersByMesa(s => {
        const cur = s[mesaId] || [];
        const next = cur.filter(n => n !== name);
        const out = { ...s };
        if (next.length === 0) delete out[mesaId]; else out[mesaId] = next;
        return out;
      });
    };
    const onBeforeUnload = () => {
      try {
        const raw = window.localStorage.getItem('cyberapp:livePlayersByMesa');
        const cur = raw ? JSON.parse(raw) : {};
        const list = (cur[mesaId] || []).filter(n => n !== name);
        if (list.length === 0) delete cur[mesaId]; else cur[mesaId] = list;
        window.localStorage.setItem('cyberapp:livePlayersByMesa', JSON.stringify(cur));
      } catch (e) {}
    };
    window.addEventListener('beforeunload', onBeforeUnload);
    // Heartbeat: atualiza timestamp deste jogador a cada 5s enquanto a aba estiver ativa.
    // (Em background, mobile throttle pode atrasar — exatamente o que queremos detectar.)
    const writeTs = () => {
      try {
        const raw = window.localStorage.getItem('cyberapp:presenceTs');
        const cur = raw ? JSON.parse(raw) : {};
        const m = { ...(cur[mesaId] || {}) };
        m[name] = Date.now();
        cur[mesaId] = m;
        window.localStorage.setItem('cyberapp:presenceTs', JSON.stringify(cur));
        setPresenceTimestamps(cur);
      } catch (e) {}
    };
    writeTs();
    const hb = setInterval(writeTs, 5000);
    return () => {
      clearInterval(hb);
      window.removeEventListener('beforeunload', onBeforeUnload);
      cleanup();
    };
  }, [role, activeMesaId, player?.name]);

  // ===== Sync entre abas via BroadcastChannel =====
  // Quando uma aba escreve em `shared`, a outra recebe e aplica sem re-broadcast.
  // Isso permite jogar com a aba do Mestre e a aba do Jogador lado a lado.
  const channelRef = useRef(null);
  const applyingFromChannelRef = useRef(false);

  useEffect(() => {
    if (typeof BroadcastChannel === 'undefined') return;
    const ch = new BroadcastChannel('cyberapp-sync');
    channelRef.current = ch;
    ch.onmessage = (ev) => {
      // Outras abas podem PEDIR uma cópia atual do shared (ex.: ao voltar do background).
      // Respondemos com o nosso estado — o solicitante escolhe o mais recente.
      if (ev.data && ev.data.type === 'request-sync') {
        try {
          ch.postMessage({ type: 'shared', payload: sharedRef.current, replyTo: ev.data.id });
        } catch (e) {}
        return;
      }
      if (!ev.data || ev.data.type !== 'shared') return;
      applyingFromChannelRef.current = true;
      // Merge inteligente do log/chat. Se o nosso local tem entries que o remoto não viu,
      // marcamos pra REENVIAR o estado mesclado de volta — assim o sender também converge.
      let needReplay = false;
      let mergedState = null;
      setSharedState(prev => {
        const incoming = ev.data.payload || {};
        const keyOf = (e) => e && e.id ? e.id : `${e?.time || 0}_${e?.text || ''}`;
        const incomingLogKeys = new Set((incoming.log || []).map(keyOf));
        const incomingChatKeys = new Set((incoming.chat || []).map(keyOf));
        const localOnlyLog = (prev.log || []).some(e => !incomingLogKeys.has(keyOf(e)));
        const localOnlyChat = (prev.chat || []).some(e => !incomingChatKeys.has(keyOf(e)));
        needReplay = localOnlyLog || localOnlyChat;
        const mergeById = (a = [], b = []) => {
          const seen = new Set();
          const out = [];
          for (const item of [...a, ...b]) {
            const key = keyOf(item);
            if (seen.has(key)) continue;
            seen.add(key);
            out.push(item);
          }
          return out.sort((x, y) => (x.time || 0) - (y.time || 0));
        };
        mergedState = {
          ...incoming,
          log: mergeById(prev.log, incoming.log),
          chat: mergeById(prev.chat, incoming.chat),
        };
        return mergedState;
      });
      queueMicrotask(() => {
        applyingFromChannelRef.current = false;
        // Replay: nossa aba tinha entries que o remetente ainda não conhece — devolve pra ele.
        if (needReplay && mergedState && channelRef.current) {
          try { channelRef.current.postMessage({ type: 'shared', payload: mergedState }); } catch (e) {}
        }
      });
    };
    return () => ch.close();
  }, []);

  const broadcastShared = (next) => {
    if (applyingFromChannelRef.current) return;
    if (channelRef.current) {
      try { channelRef.current.postMessage({ type: 'shared', payload: next }); } catch (e) {}
    }
  };

  // RECONCILIAÇÃO ao voltar do background: navegadores móveis throttle BroadcastChannel
  // e timers em abas escondidas, então mensagens podem chegar fora de ordem. Ao voltar,
  // pedimos uma cópia fresca para as outras abas e adotamos o estado MAIS RECENTE
  // (heurística: tamanho do log + chat — monotônicos). Isso corrige bugs do tipo
  // "HP voltou", "morreu mas não morreu" causados por broadcasts perdidos.
  useEffect(() => {
    const onVisibility = () => {
      if (document.visibilityState !== 'visible') return;
      const ch = channelRef.current;
      if (!ch) return;
      const reqId = `req_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
      const responses = [];
      const onMsg = (ev) => {
        if (ev.data && ev.data.type === 'shared' && ev.data.replyTo === reqId) {
          responses.push(ev.data.payload);
        }
      };
      ch.addEventListener('message', onMsg);
      try { ch.postMessage({ type: 'request-sync', id: reqId }); } catch (e) {}
      // Espera 400ms por respostas, então adota a mais "fresca".
      setTimeout(() => {
        ch.removeEventListener('message', onMsg);
        if (responses.length === 0) return;
        const scoreOf = (s) => (s?.log?.length || 0) + Object.values(s?.chats || {}).reduce((a, c) => a + (c.messages?.length || 0), 0);
        const mine = scoreOf(sharedRef.current);
        let best = sharedRef.current;
        let bestScore = mine;
        for (const r of responses) {
          const sc = scoreOf(r);
          if (sc > bestScore) { best = r; bestScore = sc; }
        }
        if (best !== sharedRef.current) {
          applyingFromChannelRef.current = true;
          setSharedState(best);
          queueMicrotask(() => { applyingFromChannelRef.current = false; });
        }
      }, 400);
    };
    document.addEventListener('visibilitychange', onVisibility);
    return () => document.removeEventListener('visibilitychange', onVisibility);
  }, []);

  // Carregar estado compartilhado ao montar
  useEffect(() => {
    (async () => {
      const saved = await storage.get('cyberapp-shared');
      // Se o storage existe E é da mesma versão E não está com NaN, usa.
      // Caso contrário, ignora e usa o estado inicial.
      if (saved && saved.version === STATE_VERSION && Number.isFinite(saved.playerHP)) {
        setSharedState({ ...initialSharedState, ...saved });
      } else {
        // Storage antigo ou corrompido — limpa e usa o inicial
        storage.set('cyberapp-shared', initialSharedState);
      }
    })();
  }, []);

  // CRONÔMETRO: lê do ref e escreve diretamente no state — sem race com setShared
  // (NÃO há polling de storage rodando, então cheats não são sobrescritos)
  useEffect(() => {
    if (!shared.isRunning) return;
    // Só a aba do Mestre dirige o cronômetro — evita drift entre abas.
    // A aba do Jogador recebe o tick via BroadcastChannel.
    if (role !== 'master') return;
    // Mesa offline → cronômetro pausa
    if (shared.tableOnline === false) return;
    const tick = setInterval(() => {
      setSharedState(prev => {
        const next = { ...prev, elapsedSeconds: prev.elapsedSeconds + 1 };
        // Broadcast do tick pra outras abas
        if (channelRef.current && !applyingFromChannelRef.current) {
          try { channelRef.current.postMessage({ type: 'shared', payload: next }); } catch (e) {}
        }
        return next;
      });
    }, 1000);
    return () => clearInterval(tick);
  }, [shared.isRunning, role, shared.tableOnline]);

  // Persistir o cronômetro a cada 5 segundos (pra sobreviver à troca de papel)
  useEffect(() => {
    const save = setInterval(() => {
      storage.set('cyberapp-shared', sharedRef.current);
    }, 5000);
    return () => clearInterval(save);
  }, []);

  const setShared = (updater) => {
    setSharedState(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater;
      // Persiste imediatamente em mudanças de cheats/ações do usuário
      storage.set('cyberapp-shared', next);
      // Sincroniza com outras abas
      broadcastShared(next);
      // Sincroniza com Firebase (cross-device)
      if (activeMesaId) {
        firebaseWrite(`shared/mesaShared/${activeMesaId}`, next);
      }
      return next;
    });
  };

  // Firebase listener para o estado compartilhado da mesa ativa (cross-device sync)
  useEffect(() => {
    if (!activeMesaId) return;
    const dbRef = ref(db, `shared/mesaShared/${activeMesaId}`);
    const unsub = onValue(dbRef, (snapshot) => {
      const val = snapshot.val();
      if (!val || !val.version) return;
      // Merge inteligente: aceita estado remoto se tem log/chat mais longo
      setSharedState(prev => {
        const remoteScore = (val.log?.length || 0) + Object.values(val.chats || {}).reduce((a, c) => a + (c.messages?.length || 0), 0);
        const localScore = (prev.log?.length || 0) + Object.values(prev.chats || {}).reduce((a, c) => a + (c.messages?.length || 0), 0);
        if (remoteScore >= localScore && JSON.stringify(val) !== JSON.stringify(prev)) {
          return val;
        }
        return prev;
      });
    });
    firebaseSharedUnsub.current = unsub;
    return () => unsub();
  }, [activeMesaId]);

  const addLog = (entry) => {
    setShared(prev => ({
      ...prev,
      log: [
        ...prev.log,
        { ...entry, time: Date.now(), id: `log_${Date.now()}_${Math.random().toString(36).slice(2, 8)}` },
      ],
    }));
  };

  const showToast = (msg, color = C.yellow, durationMs = 2500) => {
    setToast(msg);
    setToastColor(color);
    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
    toastTimerRef.current = setTimeout(() => setToast(null), Math.max(800, durationMs));
  };

  // === Notificações pro jogador ===
  // Observa novas entradas em shared.log e shared.chat com targetPlayer === player atual.
  const logSeenRef = useRef(0);
  const chatSeenRef = useRef(0);
  useEffect(() => {
    // Marca tudo como visto ao montar / quando o player aparece
    logSeenRef.current = (shared.log || []).length;
    chatSeenRef.current = (shared.chat || []).length;
  }, [player ? player.name : null]);

  useEffect(() => {
    if (role !== 'player' || !player) { logSeenRef.current = (shared.log || []).length; return; }
    const cur = (shared.log || []).length;
    if (cur > logSeenRef.current) {
      const newEntries = (shared.log || []).slice(logSeenRef.current);
      logSeenRef.current = cur;
      // Mostra a última notificação relevante (toast aceita uma de cada vez)
      const relevant = newEntries.filter(e => e.targetPlayer === player.name);
      const last = relevant[relevant.length - 1];
      if (last) showToast(last.text, last.color || C.yellow);
    }
  }, [shared.log && shared.log.length, role, player ? player.name : null]);

  useEffect(() => {
    if (role !== 'player' || !player) { chatSeenRef.current = (shared.chat || []).length; return; }
    const cur = (shared.chat || []).length;
    if (cur > chatSeenRef.current) {
      const newMsgs = (shared.chat || []).slice(chatSeenRef.current);
      chatSeenRef.current = cur;
      const last = newMsgs.filter(m => m.target === player.name && m.from === 'Mestre').slice(-1)[0];
      if (last) showToast(`Mestre: "${last.text}"`, C.purple);
    }
  }, [shared.chat && shared.chat.length, role, player ? player.name : null]);

  // === Notificação pro MESTRE: sussurro recebido de jogador ===
  // Conta o total de mensagens em conversas que envolvem o Mestre. Quando aumenta E a
  // nova mensagem veio de alguém que não é o Mestre, dispara um overlay rápido.
  const masterChatSeenRef = useRef(0);
  const countMasterMsgs = (() => {
    const all = shared.chats || {};
    let n = 0;
    for (const k in all) {
      const c = all[k];
      if (c && Array.isArray(c.participants) && c.participants.includes(CHAT_MASTER_ID)) {
        n += (c.messages || []).length;
      }
    }
    return n;
  })();
  useEffect(() => {
    if (role !== 'master') { masterChatSeenRef.current = countMasterMsgs; return; }
    if (countMasterMsgs > masterChatSeenRef.current) {
      // Acha a mensagem mais recente de jogador (não-Mestre) em qualquer conversa do Mestre
      const all = shared.chats || {};
      let latest = null;
      for (const k in all) {
        const c = all[k];
        if (!c || !Array.isArray(c.participants) || !c.participants.includes(CHAT_MASTER_ID)) continue;
        for (const m of (c.messages || [])) {
          if (m.from !== CHAT_MASTER_ID && (!latest || m.time > latest.time)) latest = m;
        }
      }
      masterChatSeenRef.current = countMasterMsgs;
      if (latest) showToast(`✉ ${latest.from} te mandou um sussurro`, C.purple);
    }
  }, [countMasterMsgs, role]);

  // === Notificação pro JOGADOR: sussurro recebido (de Mestre ou outro jogador) ===
  // Espelha a lógica do mestre — soma mensagens em conversas que envolvem o jogador atual
  // e dispara toast quando aumenta E a nova mensagem veio de alguém que não é ele.
  const playerChatsSeenRef = useRef(0);
  const countPlayerChatMsgs = (() => {
    if (!player) return 0;
    const all = shared.chats || {};
    let n = 0;
    for (const k in all) {
      const c = all[k];
      if (c && Array.isArray(c.participants) && c.participants.includes(player.name)) {
        n += (c.messages || []).length;
      }
    }
    return n;
  })();
  useEffect(() => {
    if (role !== 'player' || !player) { playerChatsSeenRef.current = countPlayerChatMsgs; return; }
    if (countPlayerChatMsgs > playerChatsSeenRef.current) {
      const all = shared.chats || {};
      let latest = null;
      for (const k in all) {
        const c = all[k];
        if (!c || !Array.isArray(c.participants) || !c.participants.includes(player.name)) continue;
        for (const m of (c.messages || [])) {
          if (m.from !== player.name && (!latest || m.time > latest.time)) latest = m;
        }
      }
      playerChatsSeenRef.current = countPlayerChatMsgs;
      if (latest) showToast(`✉ ${latest.from}: "${latest.text}"`, C.purple);
    }
  }, [countPlayerChatMsgs, role, player ? player.name : null]);

  const pickProfile = (slot) => {
    if (!acquireProfileLock(slot.id, tabIdRef.current)) {
      setToast(`${slot.label.toUpperCase()} JÁ ATIVO EM OUTRA ABA`);
      setToastColor(C.magenta);
      return;
    }
    setActiveProfile(slot.id);
    setActiveProfileState(slot.id);
    setRole(slot.role);
    setScreen(slot.role === 'master' ? 'master-mesas' : 'player-mesas');
  };

  const switchProfile = () => {
    if (activeProfile) releaseProfileLock(activeProfile, tabIdRef.current);
    setActiveProfile(null);
    setActiveProfileState(null);
    setRole(null);
    setPlayer(null);
    setActiveMesaId(null);
    setGmActiveMesaId(null);
    setScreen('profile-picker');
  };

  // Heartbeat do lock do perfil ativo e release ao fechar/desmontar.
  useEffect(() => {
    if (!activeProfile) return;
    const id = setInterval(() => acquireProfileLock(activeProfile, tabIdRef.current), 5000);
    const onUnload = () => releaseProfileLock(activeProfile, tabIdRef.current);
    window.addEventListener('beforeunload', onUnload);
    return () => {
      clearInterval(id);
      window.removeEventListener('beforeunload', onUnload);
      releaseProfileLock(activeProfile, tabIdRef.current);
    };
  }, [activeProfile]);

  const enterMesaAsMaster = (mesaId) => {
    // Salva o snapshot da mesa atual (se estávamos em outra) antes de trocar
    if (activeMesaId && activeMesaId !== mesaId) {
      setMesaStates(ms => ({ ...ms, [activeMesaId]: shared }));
    }
    setActiveMesaId(mesaId);
    setGmActiveMesaId(mesaId); // GM agora está presente nesta mesa
    const mesa = mesas.find(m => m.id === mesaId);
    // Hidrata do snapshot (se existir) ou cria estado fresco pra esta mesa
    const prev = mesaStates[mesaId];
    const baseState = prev ? prev : { ...initialSharedState, elapsedSeconds: 0, isRunning: false };
    setShared({
      ...baseState,
      tableOnline: true,
      activeMesaName: mesa?.name || null,
      activeMesaCode: mesa?.code || null,
      timeline: (mesa?.timeline?.length) ? mesa.timeline : (baseState.timeline || null),
      // xpMultiplier injetado das rules da mesa pra ser lido pelo combate (default 1).
      xpMultiplier: mesa?.rules?.xpMultiplier || 1,
      ...(mesa?.timeline?.length && !prev ? { currentPoint: 1 } : {}),
    });
    setScreen('master-home');
  };

  const enterMesaAsPlayer = (mesaId) => {
    const mesa = mesas.find(m => m.id === mesaId);
    if (!mesa) {
      showToast('MESA NÃO ENCONTRADA', C.magenta);
      return;
    }
    const existing = playerByMesa[mesaId];
    const gmOnline = gmActiveMesaId === mesaId;
    // GATE: entrar na mesa (criar OU re-entrar) exige GM presente.
    if (!gmOnline) {
      showToast(existing ? 'MESA OFFLINE · AGUARDE O GM' : 'AGUARDE O GM ABRIR A MESA PARA CRIAR PERSONAGEM', C.magenta);
      return;
    }
    // Salva snapshot da mesa atual antes de trocar
    if (activeMesaId && activeMesaId !== mesaId) {
      setMesaStates(ms => ({ ...ms, [activeMesaId]: shared }));
    }
    setActiveMesaId(mesaId);
    // Registra a mesa na lista pessoal do jogador (aparece em "Suas Mesas")
    setJoinedMesaIds(ids => ids.includes(mesaId) ? ids : [...ids, mesaId]);
    // Hidrata snapshot da nova mesa, ou cria fresco com regras da mesa.
    // BUG-FIX: se já estamos sincronizados com essa mesa (mesmo activeMesaCode no shared atual),
    // NÃO sobrescreve — senão um snapshot stale derruba o estado vivo das outras abas
    // (currentPoint volta ao início, HP de outros jogadores reverte, etc.).
    const prev = mesaStates[mesaId];
    const alreadyOnThisMesa = shared && shared.activeMesaCode === mesa.code;
    if (!alreadyOnThisMesa) {
      const hydrated = prev || {
        ...initialSharedState,
        elapsedSeconds: 0,
        activeMesaName: mesa.name,
        activeMesaCode: mesa.code,
        timeline: (mesa.timeline && mesa.timeline.length) ? mesa.timeline : null,
      };
      // Garante xpMultiplier sincronizado da mesa pro shared.
      setShared({ ...hydrated, xpMultiplier: mesa?.rules?.xpMultiplier || hydrated.xpMultiplier || 1 });
    }
    if (!gmOnline && existing) {
      showToast('MESA OFFLINE · aguardando o GM', C.yellow);
    }
    if (existing) {
      setPlayer(existing);
      // Marca jogador como ONLINE nesta mesa
      setLivePlayersByMesa(map => {
        const cur = map[mesaId] || [];
        return cur.includes(existing.name) ? map : { ...map, [mesaId]: [...cur, existing.name] };
      });
      setScreen('player-home');
    } else {
      setScreen('player-create');
    }
  };

  const leaveMesaAsPlayer = (mesaId) => {
    const leaving = playerByMesa[mesaId];
    setPlayerByMesa(m => { const copy = { ...m }; delete copy[mesaId]; return copy; });
    // Remove o personagem da lista do mestre + adiciona à lápide RIP
    if (leaving && leaving.name) {
      PLAYER_HOME_PULSE_SEEN.delete(leaving.name);
      setShared(s => {
        const tablePlayer = (s.tablePlayers || []).find(p => p.name === leaving.name);
        const heroSnapshot = tablePlayer || leaving;
        return {
          ...s,
          tablePlayers: (s.tablePlayers || []).filter(p => p.name !== leaving.name),
          attrBonuses: Object.fromEntries(Object.entries(s.attrBonuses || {}).filter(([k]) => k !== leaving.name)),
          fallenHeroes: [
            ...(s.fallenHeroes || []).filter(h => h.name !== leaving.name),
            { ...heroSnapshot, deathTime: Date.now(), deathReason: 'Saiu da mesa' },
          ],
        };
      });
    } else {
      // Sem personagem na mesa → segunda saída: remove a mesa da lista pessoal do jogador.
      setJoinedMesaIds(ids => ids.filter(id => id !== mesaId));
    }
  };

  const exitToMesas = () => {
    // Persiste snapshot da mesa atual antes de sair (per-mesa isolation)
    if (activeMesaId) {
      const finalState = {
        ...shared,
        isRunning: false,
        // Mesa fica online uma vez criada — só pausa explícita do GM derruba.
        // (Antes: derrubávamos ao GM sair → jogador via "offline" quando GM apenas voltava ao menu)
      };
      setMesaStates(ms => ({ ...ms, [activeMesaId]: finalState }));
      setShared(finalState);
    } else {
      setShared(s => ({ ...s, isRunning: false }));
    }
    if (role === 'master') setGmActiveMesaId(null);
    // Remove jogador da lista de online se está saindo
    if (role === 'player' && activeMesaId && player?.name) {
      setLivePlayersByMesa(map => {
        const cur = map[activeMesaId] || [];
        const next = cur.filter(n => n !== player.name);
        return { ...map, [activeMesaId]: next };
      });
    }
    setActiveMesaId(null);
    setPlayer(null);
    setScreen(role === 'master' ? 'master-mesas' : 'player-mesas');
  };

  // ============== ENCERRAR AVENTURA ==============
  // Mestre encerra a mesa no último ato. Computa highlights, gera código de cada PC,
  // salva entradas no Hall de cada slot envolvido (varre playerByMesa de todos os slots
  // pra achar quem está nesta mesa). Seta shared.finalEvent pra disparar a celebração
  // pra todas as abas. A mesa NÃO é apagada aqui — só quando o Mestre clicar "Concluir
  // e apagar" no overlay (pra dar tempo dos jogadores copiarem o código).
  const finalizeAdventure = (mesaId) => {
    const mesa = mesas.find(m => m.id === mesaId);
    if (!mesa) return;
    // IMPORTANTE: pra mesa ATIVA, `mesaStates[mesaId]` é o snapshot velho (de quando o
    // mestre entrou). Os stats/log acumulados ao vivo estão em `shared`. Sem isso, os
    // contadores de highlights vêm zerados na celebração.
    const snapshot = (mesaId === activeMesaId) ? shared : (mesaStates[mesaId] || shared);
    const highlights = computeMesaHighlights(snapshot);
    const players = (snapshot.tablePlayers || []);
    // Constrói codes por player
    const codes = {};
    for (const pc of players) {
      const inv = getMyInventory(snapshot, pc.name) || [];
      const imp = getMyImplants(snapshot, pc.name) || [];
      // Conta esta aventura como concluída pro código gerado
      const pcWithCount = { ...pc, aventurasConcluidas: (pc.aventurasConcluidas || 0) + 1 };
      const code = encodeCharacter(pcWithCount, inv, imp);
      if (code) codes[pc.name] = code;
    }
    // Salva entradas de Hall pra cada slot envolvido nesta mesa
    const mesaName = mesa.name || 'Aventura';
    const mesaSubtitle = mesa.subtitle || '';
    const finishedAt = Date.now();
    // Varre todos os slots de player; pra cada um, lê o pcObj salvo desta mesa
    for (const slot of PROFILE_SLOTS) {
      if (slot.role !== 'player') continue;
      let pbm = {};
      try { pbm = JSON.parse(window.localStorage.getItem(profileKey(slot.id, 'playerByMesa')) || '{}'); } catch (e) {}
      const pcRef = pbm[mesaId];
      if (!pcRef || !pcRef.name) continue;
      const pcLive = players.find(p => p.name === pcRef.name);
      if (!pcLive) continue;
      saveToHall(slot.id, {
        id: `hall_${finishedAt}_${slot.id}`,
        mesaName, mesaSubtitle, finishedAt,
        role: 'player',
        highlights: { mesa: highlights.mesa, mine: highlights.perPlayer[pcLive.name] || null },
        characterName: pcLive.name,
        characterCode: codes[pcLive.name] || null,
      });
    }
    // Entrada do Mestre (sem código de PC)
    saveToHall('slot-gm', {
      id: `hall_${finishedAt}_master`,
      mesaName, mesaSubtitle, finishedAt,
      role: 'master',
      highlights: { mesa: highlights.mesa, top: { killer: highlights.topKiller, hit: highlights.topHit, xp: highlights.topXP, luck: highlights.topLuck } },
      characterName: null,
      characterCode: null,
    });
    // Dispara evento compartilhado pra celebração
    setShared(s => ({ ...s, finalEvent: { highlights, codes, time: finishedAt, mesaName } }));
  };

  // Apaga a mesa de fato (chamado depois que o Mestre confirma no overlay de celebração).
  // IMPORTANTE: limpa shared.finalEvent ANTES (via broadcast) pra fechar o overlay em
  // todas as abas — senão o overlay fica grudado mesmo após a mesa ser apagada.
  const deleteMesaCompletely = (mesaId) => {
    setShared(s => ({ ...s, finalEvent: null }));
    // Pequeno timeout pra garantir que a limpeza do finalEvent propaga antes da remoção
    // da mesa (apenas pra o jogador ver o overlay fechar suavemente).
    setTimeout(() => {
      setMesas(ms => ms.filter(m => m.id !== mesaId));
      setMesaStates(ms => { const c = { ...ms }; delete c[mesaId]; return c; });
      setJoinedMesaIds(ids => ids.filter(id => id !== mesaId));
      setPlayerByMesa(p => { const c = { ...p }; delete c[mesaId]; return c; });
      if (activeMesaId === mesaId) setActiveMesaId(null);
      setScreen(role === 'master' ? 'master-mesas' : 'player-mesas');
    }, 120);
  };

  // Quando o Mestre encerra a aventura e clica "Concluir e Apagar Mesa", `shared.finalEvent`
  // transita de objeto pra null. Pra cada JOGADOR conectado, isso é o sinal de que a mesa
  // morreu — o jogador deve voltar pra seleção de perfil (não pra "Suas Mesas", que mostraria
  // a mesa apagada por um instante e geraria confusão).
  const prevFinalEventRef = useRef(null);
  useEffect(() => {
    const wasActive = !!prevFinalEventRef.current;
    const nowActive = !!(shared && shared.finalEvent);
    prevFinalEventRef.current = shared ? shared.finalEvent : null;
    if (wasActive && !nowActive && role === 'player') {
      // Aventura encerrada — sai pro seletor de perfil.
      exitToWelcomeRef.current && exitToWelcomeRef.current();
    }
  }, [shared && shared.finalEvent, role]);
  // Ref pra exitToWelcome (declarada abaixo) — usada pelo effect acima sem precisar reordenar.
  const exitToWelcomeRef = useRef(null);

  const exitToWelcome = () => {
    // Pausa cronômetro ao sair pra welcome.
    // Se quem está saindo é o GM, mesa fica offline (jogador não pode entrar sem GM).
    // Se quem está saindo é um JOGADOR, o personagem dele é removido da mesa (mestre não vê mais).
    const playerName = role === 'player' && player ? player.name : null;
    // Não filtramos o tablePlayer do jogador — o personagem é lembrado pra próxima entrada.
    const updatedShared = { ...shared, isRunning: false };
    setShared(updatedShared);
    // Persiste snapshot per-mesa antes de sair
    if (activeMesaId) {
      setMesaStates(ms => ({ ...ms, [activeMesaId]: updatedShared }));
    }
    // NÃO apaga playerByMesa[activeMesaId] — o personagem é lembrado pra próxima entrada
    if (role === 'master') {
      setGmActiveMesaId(null);
    }
    if (activeProfile) releaseProfileLock(activeProfile, tabIdRef.current);
    // Remove jogador da lista de online ao voltar ao welcome
    if (role === 'player' && activeMesaId && player?.name) {
      setLivePlayersByMesa(map => {
        const cur = map[activeMesaId] || [];
        return { ...map, [activeMesaId]: cur.filter(n => n !== player.name) };
      });
    }
    setRole(null);
    setActiveMesaId(null);
    setPlayer(null);
    setActiveProfile(null);
    setActiveProfileState(null);
    setScreen('profile-picker');
  };
  // Mantém ref atualizada — usada pelo effect de finalEvent pra sair pro profile-picker.
  exitToWelcomeRef.current = exitToWelcome;

  // Saída pós-morte: reseta o HP do jogador pra não ficar morto pra sempre,
  // pausa cronômetro e volta pra welcome
  const handleDeathExit = () => {
    const dyingPlayer = player;
    const dyingName = dyingPlayer ? dyingPlayer.name : null;
    if (dyingName) {
      PLAYER_HOME_PULSE_SEEN.delete(dyingName);
      const eulogies = [
        `☠ ${dyingName} caiu em Day City. A chuva ácida lava o sangue, mas o nome fica marcado no concreto.`,
        `☠ ${dyingName} flatlinou. Os implantes pararam de pulsar — só o silêncio do neon agora.`,
        `☠ O sinal de ${dyingName} se apagou. Mais um chrome esquecido nos becos da cidade.`,
        `☠ ${dyingName} morreu como viveu: cercado de inimigos, sem backup neural, sem segunda chance.`,
        `☠ ${dyingName} foi desconectado da carne. A mesa guarda um minuto de estática em sua memória.`,
        `☠ Eles vieram pelo ${dyingName} e levaram. Day City não chora seus mortos — apenas os arquiva.`,
        `☠ ${dyingName} se foi. Resta o eco do último heartbeat ressoando nos servidores corporativos.`,
      ];
      const eulogy = eulogies[Math.floor(Math.random() * eulogies.length)];
      addLog({
        kind: 'death',
        text: eulogy,
        color: '#FF003C',
        targetPlayer: dyingName,
      });
    }
    // Mexe SÓ no que é per-player: remove o jogador morto sem pausar a mesa nem
    // tocar campos globais (currentPoint, isRunning etc.) — os outros continuam.
    setShared(s => {
      const dyingEntry = dyingName ? (s.tablePlayers || []).find(p => p.name === dyingName) : null;
      const heroSnapshot = dyingEntry || dyingPlayer;
      if (!dyingName) return s;
      return {
        ...s,
        tablePlayers: (s.tablePlayers || []).filter(p => p.name !== dyingName),
        attrBonuses: Object.fromEntries(Object.entries(s.attrBonuses || {}).filter(([k]) => k !== dyingName)),
        inventoriesByPlayer: Object.fromEntries(Object.entries(s.inventoriesByPlayer || {}).filter(([k]) => k !== dyingName)),
        implantsByPlayer: Object.fromEntries(Object.entries(s.implantsByPlayer || {}).filter(([k]) => k !== dyingName)),
        fallenHeroes: heroSnapshot ? [
          ...(s.fallenHeroes || []).filter(h => h.name !== dyingName),
          { ...heroSnapshot, deathTime: Date.now(), deathReason: 'Caído em combate' },
        ] : (s.fallenHeroes || []),
      };
    });
    // Personagem morre: remove da mesa e volta pra lista
    if (activeMesaId) {
      setPlayerByMesa(m => { const copy = { ...m }; delete copy[activeMesaId]; return copy; });
    }
    setActiveMesaId(null);
    setPlayer(null);
    setScreen(role === 'master' ? 'master-mesas' : 'player-mesas');
  };

  const [menuOpen, setMenuOpen] = useState(false);
  const [masterMenuOpen, setMasterMenuOpen] = useState(false);
  const [debugOpen, setDebugOpen] = useState(false);

  const resetApp = () => {
    try {
      window.localStorage.removeItem('cyberapp:mesas');
      window.localStorage.removeItem('cyberapp:mesaStates');
      window.localStorage.removeItem('cyberapp:gmActiveMesaId');
      window.localStorage.removeItem('cyberapp:livePlayersByMesa');
      window.localStorage.removeItem(GM_LOCK_KEY);
      // Apaga dados per-slot de todos os perfis (joinedMesaIds e playerByMesa namespaceados) + locks + hall.
      PROFILE_SLOTS.forEach(s => {
        window.localStorage.removeItem(profileKey(s.id, 'joinedMesaIds'));
        window.localStorage.removeItem(profileKey(s.id, 'playerByMesa'));
        window.localStorage.removeItem(profileLockKey(s.id));
        window.localStorage.removeItem(hallKey(s.id));
      });
      // Legacy não-namespaced
      window.localStorage.removeItem('cyberapp:joinedMesaIds');
      window.localStorage.removeItem('cyberapp:playerByMesa');
    } catch (e) {}
    setMesas([]);
    setMesaStates({});
    setJoinedMesaIds([]);
    setGmActiveMesaId(null);
    setPlayerByMesa({});
    setSharedState(initialSharedState);
    setActiveMesaId(null);
    setPlayer(null);
    setRole(null);
    setActiveProfile(null);
    setActiveProfileState(null);
    setScreen('profile-picker');
    showToast('APP RESETADO', C.magenta);
  };

  let content;
  if (screen === 'profile-picker') {
    content = <ProfilePicker onPick={pickProfile} onReset={resetApp} myTabId={tabIdRef.current} />;
  } else if (screen === 'master-mesas') {
    content = <MasterMesas
      mesas={mesas} shared={shared} mesaStates={mesaStates} activeMesaId={activeMesaId}
      onBack={exitToWelcome} onEnter={enterMesaAsMaster}
      onOpenHall={() => setScreen('hall')}
      onCreate={() => setScreen('master-create-mesa')}
      onDelete={(mesaId) => {
        setMesas(ms => ms.filter(m => m.id !== mesaId));
        setMesaStates(ms => { const c = { ...ms }; delete c[mesaId]; return c; });
        setJoinedMesaIds(ids => ids.filter(id => id !== mesaId));
        setPlayerByMesa(p => { const c = { ...p }; delete c[mesaId]; return c; });
        if (activeMesaId === mesaId) setActiveMesaId(null);
      }}
      showToast={showToast}
    />;
  } else if (screen === 'master-create-mesa') {
    content = <MesaCreator onBack={() => setScreen('master-mesas')} showToast={showToast} onCreate={(newMesa) => {
      setMesas(ms => [...ms, newMesa]);
      // Inicializa snapshot da mesa já online — jogador pode entrar pelo código imediatamente
      setMesaStates(ms => ({
        ...ms,
        [newMesa.id]: {
          ...initialSharedState,
          tableOnline: true,
          elapsedSeconds: 0,
          isRunning: false,
          activeMesaName: newMesa.name,
          activeMesaCode: newMesa.code,
          timeline: (newMesa.timeline && newMesa.timeline.length) ? newMesa.timeline : null,
        },
      }));
      setScreen('master-mesas');
    }} />;
  } else if (screen === 'player-mesas') {
    content = <PlayerMesas
      mesas={mesas} shared={shared} mesaStates={mesaStates} activeMesaId={activeMesaId}
      playerByMesa={playerByMesa} joinedMesaIds={joinedMesaIds} gmActiveMesaId={gmActiveMesaId}
      onBack={exitToWelcome} onEnter={enterMesaAsPlayer} onLeave={leaveMesaAsPlayer}
      onOpenHall={() => setScreen('hall')}
      onJoinByCode={(mesaId) => setJoinedMesaIds(ids => ids.includes(mesaId) ? ids : [...ids, mesaId])}
      showToast={showToast}
    />;
  } else if (screen === 'master-home') {
    content = <MasterHome onNav={setScreen} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} onOpenMenu={() => setMasterMenuOpen(true)} realPlayerName={player?.name || (activeMesaId ? playerByMesa[activeMesaId]?.name : null)} onlinePlayerNames={(livePlayersByMesa && activeMesaId && livePlayersByMesa[activeMesaId]) || []} ausenteNames={Object.entries((presenceTimestamps && activeMesaId && presenceTimestamps[activeMesaId]) || {}).filter(([, t]) => (Date.now() - t) > AUSENTE_THRESHOLD_MS).map(([n]) => n)} onFinalize={() => activeMesaId && finalizeAdventure(activeMesaId)} />;
  } else if (screen === 'master-players') {
    content = <MasterPlayers onBack={() => setScreen('master-home')} onNav={setScreen} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} onOpenPlayerScreen={(s, name) => { setSelectedPlayer(name); setScreen(s); }} onlinePlayerNames={(livePlayersByMesa && activeMesaId && livePlayersByMesa[activeMesaId]) || []} ausenteNames={Object.entries((presenceTimestamps && activeMesaId && presenceTimestamps[activeMesaId]) || {}).filter(([, t]) => (Date.now() - t) > AUSENTE_THRESHOLD_MS).map(([n]) => n)} />;
  } else if (screen === 'master-player-challenges') {
    content = <MasterChallenges target={selectedPlayer ? { name: selectedPlayer } : null} onBack={() => setScreen('master-players')} onNav={setScreen} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} />;
  } else if (screen === 'master-player-advantage' || screen === 'master-player-disadvantage') {
    content = <MasterAttrAdjust delta={screen === 'master-player-advantage' ? +1 : -1} playerName={selectedPlayer} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} onBack={() => setScreen('master-players')} />;
  } else if (screen === 'master-player-inventory') {
    content = <MasterPlayerInventoryScreen playerName={selectedPlayer} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} onBack={() => setScreen('master-players')} />;
  } else if (screen === 'master-player-implants') {
    content = <MasterPlayerImplantsScreen playerName={selectedPlayer} shared={shared} onBack={() => setScreen('master-players')} />;
  } else if (screen === 'master-npcs') {
    content = <MasterNPCs onBack={() => setScreen('master-home')} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} />;
  } else if (screen === 'master-challenges') {
    content = <MasterChallenges onBack={() => setScreen('master-home')} onNav={setScreen} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} />;
  } else if (screen === 'hall') {
    content = <HallScreen onBack={() => setScreen(role === 'master' ? 'master-mesas' : 'player-mesas')} profileSlot={activeProfile} role={role} showToast={showToast} />;
  } else if (screen === 'guide') {
    content = <GuideScreen onBack={() => setScreen(role === 'master' ? 'master-home' : 'player-home')} />;
  } else if (screen === 'master-whispers') {
    content = <MasterWhispers
      onBack={() => setScreen('master-home')}
      shared={shared}
      setShared={setShared}
      addLog={addLog}
      showToast={showToast}
      onOpenChat={(name) => { setSelectedPlayer(name); setScreen('master-chat-from-list'); }}
    />;
  } else if (screen === 'master-chat-from-list') {
    content = <MasterChat onBack={() => setScreen('master-whispers')} shared={shared} setShared={setShared} target={selectedPlayer || 'Jogador'} />;
  } else if (screen === 'master-chat') {
    content = <MasterChat onBack={() => setScreen('master-players')} shared={shared} setShared={setShared} target={selectedPlayer || 'Jogador'} />;
  } else if (screen === 'master-hack') {
    content = <MasterHack onBack={() => setScreen('master-home')} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} />;
  } else if (screen === 'master-log') {
    content = <LogScreen onBack={() => setScreen('master-home')} shared={shared} role="master" />;
  } else if (screen === 'master-rip') {
    content = <MasterRIP onBack={() => setScreen('master-home')} shared={shared} />;
  } else if (screen === 'player-create') {
    const activeMesa = mesas.find(m => m.id === activeMesaId);
    const mesaRules = mergeRules(activeMesa && activeMesa.rules);
    content = <PlayerCreate showToast={showToast} mesaRules={mesaRules} onBack={() => setScreen('player-mesas')} onDone={(p) => {
      setPlayer(p);
      if (activeMesaId) setPlayerByMesa(m => ({ ...m, [activeMesaId]: p }));
      // Cyberpunk: dobro de sorte (10/10). Outros usam regras da mesa.
      const cyber = p.classId === 'cyberpunk';
      const kit = p.kitId && p.kitId !== '_imported' ? getKit(p.kitId) : null;
      // HP base + bônus do kit + ganho por nível inicial.
      // Se importado, usa nível do código (não o da mesa) e ignora bônus de kit.
      const startLevel = p._imported ? p._imported.level : mesaRules.startingLevel;
      const baseMaxHP = mesaRules.baseHP + (kit && kit.bonus && kit.bonus.maxHP ? kit.bonus.maxHP : 0);
      const maxHP = baseMaxHP + (startLevel - 1) * HP_PER_LEVEL;
      // Cyberpunk: dobro da sorte da mesa, com cap em 10 (balanceamento)
      const startLuckBase = cyber ? Math.min(10, mesaRules.startingLuck * 2) : mesaRules.startingLuck;
      // Dinheiro: importado usa o do código; senão regras da mesa.
      const startMoney = p._imported ? p._imported.money : mesaRules.startingMoney;
      // XP cumulativo pra estar no nível inicial: soma das thresholds k*1000 (k=1..startLevel-1)
      const startXP = 0; // começa "zerado" no nível inicial
      // Se importado, reconstrói gear via makeItem (templateId + raridade). Senão usa kit.
      let inv = kit ? [kit.weapon, kit.consumable] : null;
      let impl = kit ? [kit.implant] : null;
      if (p._imported) {
        const im = p._imported;
        inv = [];
        if (im.weapon) {
          const w = makeItem(im.weapon.templateId, im.weapon.rarity);
          if (w) inv.push({ ...w, equipped: true });
        }
        impl = (im.implants || []).map(i => {
          const x = makeItem(i.templateId, i.rarity);
          return x ? { ...x, equipped: true } : null;
        }).filter(Boolean);
      }
      // Pontos de atributo bônus por nível inicial. NÃO conceder quando o PC veio
      // importado — os atributos do código já refletem todos os ups gastos.
      const bonusAttrPts = p._imported ? 0 : Math.max(0, startLevel - 1);
      // BUG-FIX: implantes equipados com hpBonus precisam entrar no HP inicial,
      // senão o jogador nasce com a barra parcial (ex.: kit Verde: 30/40 em vez de 40/40).
      const startEquippedHpBonus = (impl || []).filter(i => i && i.equipped).reduce((a, i) => a + (i.hpBonus || 0), 0);
      const startEquippedLuckBonus = (impl || []).filter(i => i && i.equipped).reduce((a, i) => a + (i.luckBonus || 0), 0);
      setShared(s => ({
        ...s,
        // Campos per-player: nada de singular global (vazaria stats entre jogadores).
        pendingAttrByPlayer: { ...(s.pendingAttrByPlayer || {}), [p.name]: bonusAttrPts },
        inventoriesByPlayer: { ...(s.inventoriesByPlayer || {}), [p.name]: inv || [] },
        implantsByPlayer: { ...(s.implantsByPlayer || {}), [p.name]: impl || [] },
        tablePlayers: [
          ...(s.tablePlayers || []).filter(x => x.name !== p.name),
          {
            ...p, isRealPlayer: true,
            // maxHp armazena o BASE; o render soma implantHpBonus dinamicamente.
            // hp inicial inclui o bônus pra começar com a barra cheia efetiva.
            hp: maxHP + startEquippedHpBonus, maxHp: maxHP,
            luck: startLuckBase + startEquippedLuckBonus, luckMax: startLuckBase,
            money: startMoney, xp: startXP, level: startLevel,
          },
        ],
      }));
      setScreen('player-home');
    }} />;
  } else if (screen === 'player-home') {
    content = <PlayerHome player={player} shared={shared} setShared={setShared} onMenu={() => setMenuOpen(true)} onNav={setScreen} addLog={addLog} showToast={showToast} onDeathExit={handleDeathExit} />;
  } else if (screen === 'player-whisper') {
    content = <PlayerWhisper onBack={() => setScreen('player-home')} player={player} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast} />;
  } else if (screen === 'player-inventory') {
    content = <PlayerInventory onBack={() => setScreen('player-home')} addLog={addLog} showToast={showToast} shared={shared} setShared={setShared} player={player} />;
  } else if (screen === 'player-implants') {
    content = <PlayerImplants onBack={() => setScreen('player-home')} shared={shared} setShared={setShared} player={player} addLog={addLog} showToast={showToast} />;
  } else if (screen === 'player-sheet') {
    content = <PlayerSheet onBack={() => setScreen('player-home')} player={player} shared={shared} setShared={setShared} addLog={addLog} showToast={showToast}
      onUpdatePlayer={(patch) => {
        setPlayer(p => p ? { ...p, ...patch } : p);
        if (activeMesaId) setPlayerByMesa(m => ({ ...m, [activeMesaId]: { ...(m[activeMesaId] || {}), ...patch } }));
      }}
    />;
  } else if (screen === 'player-party') {
    content = <PlayerParty onBack={() => setScreen('player-home')} player={player} shared={shared} />;
  } else if (screen === 'player-log') {
    content = <LogScreen onBack={() => setScreen('player-home')} shared={shared} role="player" />;
  }

  return (
    <div className="cyber-root" style={{
      minHeight: '100vh',
      background: C.bg,
      maxWidth: 420,
      margin: '0 auto',
      position: 'relative',
      boxShadow: '0 0 60px rgba(252, 238, 10, 0.05)',
    }}>
      <GlobalStyle />
      {content}
      {/* Popup compartilhado de sussurro pra mesa toda — aparece pra todos em qualquer tela */}
      {(role === 'master' || role === 'player') && shared && (
        <MesaWhisperOverlay shared={shared} setShared={setShared} />
      )}
      {/* Celebração de fim de aventura — aparece pra mestre + jogadores */}
      {(role === 'master' || role === 'player') && shared && shared.finalEvent && (
        <CelebrationOverlay
          shared={shared}
          role={role}
          playerName={player?.name || null}
          onMasterConfirm={() => activeMesaId && deleteMesaCompletely(activeMesaId)}
        />
      )}
      {menuOpen && role === 'player' && (
        <PlayerMenu
          onClose={() => setMenuOpen(false)}
          onNav={setScreen}
          shared={shared}
          player={player}
          showToast={showToast}
          onDebug={() => setDebugOpen(true)}
          onSwitchRole={exitToWelcome}
          onExit={() => { setMenuOpen(false); exitToWelcome(); }}
        />
      )}
      {masterMenuOpen && role === 'master' && (
        <MasterMenu
          onClose={() => setMasterMenuOpen(false)}
          onNav={setScreen}
          shared={shared}
          setShared={setShared}
          onToggleOnline={(newVal) => {
            if (activeMesaId) {
              setMesaStates(ms => ({ ...ms, [activeMesaId]: { ...(ms[activeMesaId] || shared), tableOnline: newVal } }));
            }
          }}
          showToast={showToast}
          onDebug={() => setDebugOpen(true)}
          onExit={exitToWelcome}
        />
      )}
      <DebugPanel
        open={debugOpen}
        onClose={() => setDebugOpen(false)}
        role={role}
        shared={shared}
        setShared={setShared}
        showToast={showToast}
        player={player}
      />
      <PauseOverlay
        visible={role === 'player' && !!activeMesaId && shared.tableOnline === false}
        onExit={exitToWelcome}
      />
      <CombatOverlay shared={shared} />
      <ChallengeRunner
        pending={shared.pendingMinigame}
        role={role}
        isPlayer={role === 'player' && !!player}
        playerName={player ? player.name : null}
        setShared={setShared}
        addLog={addLog}
        showToast={showToast}
      />
      <Toast msg={toast} color={toastColor} />
    </div>
  );
}
